var tipuesearch = {"pages":[{"title":" SpecialMatrices ","text":"SpecialMatrices Warning This API documentation for the SpecialMatrices pacakge is a work in progress.\n   It is build from the source code in the main branch and does not track the current development in dev or any other branches.\n   If you use another branch, please refer to the in-code documentation.\n   Use the navigation bar at the top of the screen to browse modules , procedures , source files , etc.\n   The listings near the bootom of the page are incomplete. Developer Info Jean-Christophe Loiseau","tags":"home","loc":"index.html"},{"title":"Bidiagonal – SpecialMatrices ","text":"type, public :: Bidiagonal Base type used to define a Bidiagonal matrix of size [n x n] with diagonals given by\nthe rank-1 arrays dv and ev . The character which determines whether ev defines the\nsub-diagonal ( which = \"L\" , default) or the super-diagonal ( which = \"U\" ). Components Type Visibility Attributes Name Initial real(kind=dp), public, allocatable :: dv (:) Diagonal elements real(kind=dp), public, allocatable :: ev (:) Diagonal elements integer(kind=ilp), public :: n Dimension of the matrix. character(len=1), public :: which Whether it is lower- or upper-bidiagonal. Constructor public        interface Bidiagonal This interface provides different methods to construct a Bidiagonal matrix.\nOnly double precision is supported currently. Only the non-zero elements of are stored, i.e. Syntax Construct a Bidiagonal matrix filled with zeros: integer , parameter :: n = 100 type ( Bidiagonal ) :: A A = Bidiagonal ( n ) Construct a Bidiagonal matrix from rank-1 arrays: integer , parameter :: n real ( dp ), allocatable :: dv (:), ev (:) type ( Bidiagonal ) :: A integer :: i ev = [( i , i = 1 , n )]; dv = [( 2 * i , i = 1 , n )] A = Bidiagonal ( dv , ev , which = \"L\" ) Construct a Bidiagonal matrix with constant diagonals: integer , parameter :: n real ( dp ), parameter :: e = 1.0_dp , d = 2.0_dp type ( Bidiagonal ) :: A A = Bidiagonal ( d , e , n , which = \"L\" ) private pure module function construct_bidiag(dv, ev, which) result(A) Utility function to construct a Bidiagonal matrix from rank-1 arrays. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: dv (:) Diagonal elements of the matrix. real(kind=dp), intent(in) :: ev (:) Diagonal elements of the matrix. character(len=1), intent(in), optional :: which Whether A has a sub- or super-diagonal. Return Value type( Bidiagonal ) Corresponding bidiagonal matrix. private pure module function construct_constant_bidiag(d, e, n, which) result(A) Utility function to construct a Bidiagonal matrix with constant elements. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: d Constant diagonal elements. real(kind=dp), intent(in) :: e Constant diagonal elements. integer(kind=ilp), intent(in) :: n Dimension of the matrix. character(len=1), intent(in), optional :: which Whether A has a sub- or super-diagonal. Return Value type( Bidiagonal ) Corresponding bidiagonal matrix. private pure module function initialize_bidiag(n, which) result(A) Utility function to construct a Bidiagonal matrix filled with zeros. Arguments Type Intent Optional Attributes Name integer(kind=ilp), intent(in) :: n Dimension of the matrix. character(len=1), intent(in), optional :: which Whether A has a sub- or super-diagonal. Return Value type( Bidiagonal ) Corresponding bidiagonal matrix.","tags":"","loc":"type/bidiagonal.html"},{"title":"Diagonal – SpecialMatrices ","text":"type, public :: Diagonal Base type used to define a Diagonal matrix of size [n x n] with diagonal given by the\nrank-1 array dv . Components Type Visibility Attributes Name Initial real(kind=dp), public, allocatable :: dv (:) Diagonal elements of the matrix. integer(kind=ilp), public :: n Dimension of the matrix. Constructor public        interface Diagonal This interface provides different methods to construct a Diagonal matrix.\nOnly double precision is supported currently. Only the diagonal elements\nof are being stored, i.e. Syntax Construct a Diagonal matrix filled with zeros: integer , parameter :: n = 100 type ( Diagonal ) :: A A = Diagonal ( n ) Construct a Diagonal matrix from a vector. integer , parameter :: n = 100 real ( dp ), allocatable :: dv (:) type ( Diagonal ) :: A integer :: i dv = [( i , i = 1 , n )]; A = Diagonal ( dv ) Construct a Diagonal matrix with constant diagonal element. integer , parameter :: n = 100 real ( dp ), parameter :: d = 2.0_dp type ( Diagonal ) :: A A = Diagonal ( d , n ) Construct a Diagonal matrix from a standard Fortran rank-2 array. integer , parameter :: n = 100 real ( dp ) :: B ( n , n ) type ( Diagonal ) :: A call random_number ( B ); A = Diagonal ( B ) private pure module function construct_constant_diag(d, n) result(A) Utility function to construct a Diagonal matrix with constant diagonal element. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: d Constant diagonal element of the matrix. integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( Diagonal ) Corresponding diagonal matrix. private module function construct_dense_to_diag(A) result(B) Utility function to construct a Diagonal matrix from a rank-2 array. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: A (:,:) Dense [n x n] matrix from which to construct the Diagonal one. Return Value type( Diagonal ) Corresponding diagonal matrix. private pure module function construct_diag(dv) result(A) Utility function to construct a Diagonal matrix from a rank-1 array. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: dv (:) Diagonal elements of the matrix. Return Value type( Diagonal ) Corresponding diagonal matrix. private pure module function initialize_diag(n) result(A) Utility function to construct a Diagonal matrix filled with zeros. Arguments Type Intent Optional Attributes Name integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( Diagonal ) Corresponding diagonal matrix.","tags":"","loc":"type/diagonal.html"},{"title":"SymTridiagonal – SpecialMatrices ","text":"type, public :: SymTridiagonal Base type used to define a SymTridiagonal matrix of size [n x n] with diagonal elements\ngiven by the rank-1 arrays dv (diagonal) and ev (sub- and super-diagonal). Components Type Visibility Attributes Name Initial real(kind=dp), public, allocatable :: dv (:) Tridiagonal elements. real(kind=dp), public, allocatable :: ev (:) Tridiagonal elements. integer(kind=ilp), public :: n Dimension of the matrix. Constructor public        interface SymTridiagonal This interface provides different methods to construct a SymTridiagonal matrix.\nOnly double precision is supported currently. Only the non-zero elements of are stored, i.e. Syntax Construct a SymTridiagonal matrix filled with zeros: integer , parameter :: n = 100 type ( SymTridiagonal ) :: A A = SymTridiagonal ( n ) Construct a SymTridiagonal matrix from rank-1 arrays: integer , parameter :: n real ( dp ), allocatable :: ev (:), dv (:) type ( SymTridiagonal ) :: A integer :: i dv = [( i , i = 1 , n )]; ev = [( 2 * i , i = 1 , n )] A = Tridiagonal ( dv , ev ) Construct a SymTridiagonal matrix with constant diagonals: integer , parameter :: n real ( dp ), parameter :: d = 1.0_dp , e = 2.0_dp type ( SymTridiagonal ) :: A A = SymTridiagonal ( d , e , n ) private pure module function construct_constant_symtridiag(d, e, n) result(A) Utility function to create a SymTridiagonal matrix with constant diagonal elements. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: d Constant diagonal elements of the matrix. real(kind=dp), intent(in) :: e Constant diagonal elements of the matrix. integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( SymTridiagonal ) Corresponding symmetric tridiagonal matrix. private pure module function construct_symtridiag(dv, ev) result(A) Utility function to create a SymTridiagonal matrix from rank-1 arrays. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: dv (:) Diagonal elements of the matrix. real(kind=dp), intent(in) :: ev (:) Diagonal elements of the matrix. Return Value type( SymTridiagonal ) Corresponding symmetric tridiagonal matrix. private pure module function initialize_symtridiag(n) result(A) Utility function to create a SymTridiagonal matrix filled with zeros. Arguments Type Intent Optional Attributes Name integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( SymTridiagonal ) Corresponding symmetric tridiagonal matrix.","tags":"","loc":"type/symtridiagonal.html"},{"title":"Tridiagonal – SpecialMatrices ","text":"type, public :: Tridiagonal Base type used to define a Tridiagonal matrix of size [n x n] with diagonal elements\ngiven by the rank-1 arrays dl (sub-diagonal), d (diagonal) and du (super-diagonal). Components Type Visibility Attributes Name Initial real(kind=dp), public, allocatable :: d (:) Tridiagonal elements. real(kind=dp), public, allocatable :: dl (:) Tridiagonal elements. real(kind=dp), public, allocatable :: du (:) Tridiagonal elements. integer(kind=ilp), public :: n Dimension of the matrix. Constructor public        interface Tridiagonal This interface provides different methods to construct a Tridiagonal matrix.\nOnly double precision is supported currently. Only the non-zero elements of are stored, i.e. Syntax Construct a Tridiagonal matrix filled with zeros: integer , parameter :: n = 100 type ( Tridiagonal ) :: A A = Tridiagonal ( n ) Construct a Tridiagonal matrix from rank-1 arrays: integer , parameter :: n real ( dp ), allocatable :: dl (:), d (:), du (:) type ( Tridiagonal ) :: A integer :: i dl = [( i , i = 1 , n )]; d = [( 2 * i , i = 1 , n )]; dl = [( 3 * i , i = 1 , n )] A = Tridiagonal ( dl , d , du ) Construct a Tridiagonal matrix with constant diagonals: integer , parameter :: n real ( dp ), parameter :: dl = 1.0_dp , d = 2.0_dp , du = 3.0_dp type ( Tridiagonal ) :: A A = Tridiagonal ( dl , d , du , n ) Construct a Tridiagonal matrix from a standard Fortran rank-2 array: integer , parameter :: n = 100 real ( dp ) :: B ( n , n ) type ( Tridiagonal ) :: A call random_number ( B ); A = Tridiagonal ( B ) private pure module function construct_constant_tridiag(l, d, u, n) result(A) Utility function to construct a Tridiagonal matrix with constant elements. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: l Constant diagonal elements. real(kind=dp), intent(in) :: d Constant diagonal elements. real(kind=dp), intent(in) :: u Constant diagonal elements. integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( Tridiagonal ) Corresponding tridiagonal matrix. private module function construct_dense_to_tridiag(A) result(B) Utility function to construct a Tridiagonal matrix from a rank-2 array. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: A (:,:) Dense [n x n] matrix from which to construct the Tridiagonal one. Return Value type( Tridiagonal ) Corresponding tridiagonal matrix. private pure module function construct_tridiag(dl, d, du) result(A) Utility function to construct a Tridiagonal matrix from a set of rank-1 arrays. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: dl (:) Diagonal elements of the matrix. real(kind=dp), intent(in) :: d (:) Diagonal elements of the matrix. real(kind=dp), intent(in) :: du (:) Diagonal elements of the matrix. Return Value type( Tridiagonal ) Corresponding tridiagonal matrix. private pure module function initialize_tridiag(n) result(A) Utility function to construct a Tridiagonal matrix filled with zeros. Arguments Type Intent Optional Attributes Name integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( Tridiagonal ) Corresponding tridiagonal matrix.","tags":"","loc":"type/tridiagonal.html"},{"title":"say_hello – SpecialMatrices","text":"public  subroutine say_hello() Arguments None Source Code subroutine say_hello print * , \"Hello, SpecialMatrices!\" end subroutine say_hello","tags":"","loc":"proc/say_hello.html"},{"title":"Bidiagonal – SpecialMatrices","text":"public interface Bidiagonal This interface provides different methods to construct a Bidiagonal matrix.\nOnly double precision is supported currently. Only the non-zero elements of are stored, i.e. Syntax Construct a Bidiagonal matrix filled with zeros: integer , parameter :: n = 100 type ( Bidiagonal ) :: A A = Bidiagonal ( n ) Construct a Bidiagonal matrix from rank-1 arrays: integer , parameter :: n real ( dp ), allocatable :: dv (:), ev (:) type ( Bidiagonal ) :: A integer :: i ev = [( i , i = 1 , n )]; dv = [( 2 * i , i = 1 , n )] A = Bidiagonal ( dv , ev , which = \"L\" ) Construct a Bidiagonal matrix with constant diagonals: integer , parameter :: n real ( dp ), parameter :: e = 1.0_dp , d = 2.0_dp type ( Bidiagonal ) :: A A = Bidiagonal ( d , e , n , which = \"L\" ) Functions private pure module function construct_bidiag(dv, ev, which) result(A) Utility function to construct a Bidiagonal matrix from rank-1 arrays. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: dv (:) Diagonal elements of the matrix. real(kind=dp), intent(in) :: ev (:) Diagonal elements of the matrix. character(len=1), intent(in), optional :: which Whether A has a sub- or super-diagonal. Return Value type( Bidiagonal ) Corresponding bidiagonal matrix. private pure module function construct_constant_bidiag(d, e, n, which) result(A) Utility function to construct a Bidiagonal matrix with constant elements. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: d Constant diagonal elements. real(kind=dp), intent(in) :: e Constant diagonal elements. integer(kind=ilp), intent(in) :: n Dimension of the matrix. character(len=1), intent(in), optional :: which Whether A has a sub- or super-diagonal. Return Value type( Bidiagonal ) Corresponding bidiagonal matrix. private pure module function initialize_bidiag(n, which) result(A) Utility function to construct a Bidiagonal matrix filled with zeros. Arguments Type Intent Optional Attributes Name integer(kind=ilp), intent(in) :: n Dimension of the matrix. character(len=1), intent(in), optional :: which Whether A has a sub- or super-diagonal. Return Value type( Bidiagonal ) Corresponding bidiagonal matrix.","tags":"","loc":"interface/bidiagonal.html"},{"title":"Diagonal – SpecialMatrices","text":"public interface Diagonal This interface provides different methods to construct a Diagonal matrix.\nOnly double precision is supported currently. Only the diagonal elements\nof are being stored, i.e. Syntax Construct a Diagonal matrix filled with zeros: integer , parameter :: n = 100 type ( Diagonal ) :: A A = Diagonal ( n ) Construct a Diagonal matrix from a vector. integer , parameter :: n = 100 real ( dp ), allocatable :: dv (:) type ( Diagonal ) :: A integer :: i dv = [( i , i = 1 , n )]; A = Diagonal ( dv ) Construct a Diagonal matrix with constant diagonal element. integer , parameter :: n = 100 real ( dp ), parameter :: d = 2.0_dp type ( Diagonal ) :: A A = Diagonal ( d , n ) Construct a Diagonal matrix from a standard Fortran rank-2 array. integer , parameter :: n = 100 real ( dp ) :: B ( n , n ) type ( Diagonal ) :: A call random_number ( B ); A = Diagonal ( B ) Functions private pure module function construct_constant_diag(d, n) result(A) Utility function to construct a Diagonal matrix with constant diagonal element. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: d Constant diagonal element of the matrix. integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( Diagonal ) Corresponding diagonal matrix. private module function construct_dense_to_diag(A) result(B) Utility function to construct a Diagonal matrix from a rank-2 array. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: A (:,:) Dense [n x n] matrix from which to construct the Diagonal one. Return Value type( Diagonal ) Corresponding diagonal matrix. private pure module function construct_diag(dv) result(A) Utility function to construct a Diagonal matrix from a rank-1 array. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: dv (:) Diagonal elements of the matrix. Return Value type( Diagonal ) Corresponding diagonal matrix. private pure module function initialize_diag(n) result(A) Utility function to construct a Diagonal matrix filled with zeros. Arguments Type Intent Optional Attributes Name integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( Diagonal ) Corresponding diagonal matrix.","tags":"","loc":"interface/diagonal.html"},{"title":"SymTridiagonal – SpecialMatrices","text":"public interface SymTridiagonal This interface provides different methods to construct a SymTridiagonal matrix.\nOnly double precision is supported currently. Only the non-zero elements of are stored, i.e. Syntax Construct a SymTridiagonal matrix filled with zeros: integer , parameter :: n = 100 type ( SymTridiagonal ) :: A A = SymTridiagonal ( n ) Construct a SymTridiagonal matrix from rank-1 arrays: integer , parameter :: n real ( dp ), allocatable :: ev (:), dv (:) type ( SymTridiagonal ) :: A integer :: i dv = [( i , i = 1 , n )]; ev = [( 2 * i , i = 1 , n )] A = Tridiagonal ( dv , ev ) Construct a SymTridiagonal matrix with constant diagonals: integer , parameter :: n real ( dp ), parameter :: d = 1.0_dp , e = 2.0_dp type ( SymTridiagonal ) :: A A = SymTridiagonal ( d , e , n ) Functions private pure module function construct_constant_symtridiag(d, e, n) result(A) Utility function to create a SymTridiagonal matrix with constant diagonal elements. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: d Constant diagonal elements of the matrix. real(kind=dp), intent(in) :: e Constant diagonal elements of the matrix. integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( SymTridiagonal ) Corresponding symmetric tridiagonal matrix. private pure module function construct_symtridiag(dv, ev) result(A) Utility function to create a SymTridiagonal matrix from rank-1 arrays. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: dv (:) Diagonal elements of the matrix. real(kind=dp), intent(in) :: ev (:) Diagonal elements of the matrix. Return Value type( SymTridiagonal ) Corresponding symmetric tridiagonal matrix. private pure module function initialize_symtridiag(n) result(A) Utility function to create a SymTridiagonal matrix filled with zeros. Arguments Type Intent Optional Attributes Name integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( SymTridiagonal ) Corresponding symmetric tridiagonal matrix.","tags":"","loc":"interface/symtridiagonal.html"},{"title":"Tridiagonal – SpecialMatrices","text":"public interface Tridiagonal This interface provides different methods to construct a Tridiagonal matrix.\nOnly double precision is supported currently. Only the non-zero elements of are stored, i.e. Syntax Construct a Tridiagonal matrix filled with zeros: integer , parameter :: n = 100 type ( Tridiagonal ) :: A A = Tridiagonal ( n ) Construct a Tridiagonal matrix from rank-1 arrays: integer , parameter :: n real ( dp ), allocatable :: dl (:), d (:), du (:) type ( Tridiagonal ) :: A integer :: i dl = [( i , i = 1 , n )]; d = [( 2 * i , i = 1 , n )]; dl = [( 3 * i , i = 1 , n )] A = Tridiagonal ( dl , d , du ) Construct a Tridiagonal matrix with constant diagonals: integer , parameter :: n real ( dp ), parameter :: dl = 1.0_dp , d = 2.0_dp , du = 3.0_dp type ( Tridiagonal ) :: A A = Tridiagonal ( dl , d , du , n ) Construct a Tridiagonal matrix from a standard Fortran rank-2 array: integer , parameter :: n = 100 real ( dp ) :: B ( n , n ) type ( Tridiagonal ) :: A call random_number ( B ); A = Tridiagonal ( B ) Functions private pure module function construct_constant_tridiag(l, d, u, n) result(A) Utility function to construct a Tridiagonal matrix with constant elements. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: l Constant diagonal elements. real(kind=dp), intent(in) :: d Constant diagonal elements. real(kind=dp), intent(in) :: u Constant diagonal elements. integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( Tridiagonal ) Corresponding tridiagonal matrix. private module function construct_dense_to_tridiag(A) result(B) Utility function to construct a Tridiagonal matrix from a rank-2 array. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: A (:,:) Dense [n x n] matrix from which to construct the Tridiagonal one. Return Value type( Tridiagonal ) Corresponding tridiagonal matrix. private pure module function construct_tridiag(dl, d, du) result(A) Utility function to construct a Tridiagonal matrix from a set of rank-1 arrays. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: dl (:) Diagonal elements of the matrix. real(kind=dp), intent(in) :: d (:) Diagonal elements of the matrix. real(kind=dp), intent(in) :: du (:) Diagonal elements of the matrix. Return Value type( Tridiagonal ) Corresponding tridiagonal matrix. private pure module function initialize_tridiag(n) result(A) Utility function to construct a Tridiagonal matrix filled with zeros. Arguments Type Intent Optional Attributes Name integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( Tridiagonal ) Corresponding tridiagonal matrix.","tags":"","loc":"interface/tridiagonal.html"},{"title":"dense – SpecialMatrices","text":"public interface dense This interface provides methods to convert a matrix of one the types defined in SpecialMatrix to a regular rank-2 array. Syntax B = dense ( A ) Arguments A :  Matrix of Diagonal , Bidiagonal , Tridiagonal or SymTridiagonal type.\n         It is an intent(in) argument. B :  Rank-2 array representation of the matrix . Functions private pure module function bidiag_to_dense(A) result(B) Utility function to convert a Bidiagonal matrix to a regular rank-2 array. Arguments Type Intent Optional Attributes Name type( Bidiagonal ), intent(in) :: A Input bidiagonal matrix. Return Value real(kind=dp), (A%n,A%n) Output dense rank-2 array. private pure module function diag_to_dense(A) result(B) Utility function to convert a Diagonal matrix to a regular rank-2 array. Arguments Type Intent Optional Attributes Name type( Diagonal ), intent(in) :: A Input diagonal matrix. Return Value real(kind=dp), (A%n,A%n) Output dense rank-2 array. private pure module function symtridiag_to_dense(A) result(B) Utility function to convert a SymTridiagonal matrix to a regular rank-2 array. Arguments Type Intent Optional Attributes Name type( SymTridiagonal ), intent(in) :: A Input symmetric tridiagonal matrix. Return Value real(kind=dp), (A%n,A%n) Output dense rank-2 array. private pure module function tridiag_to_dense(A) result(B) Utility function to convert a Tridiagonal matrix to a regular rank-2 array. Arguments Type Intent Optional Attributes Name type( Tridiagonal ), intent(in) :: A Input tridiagonal matrix. Return Value real(kind=dp), (A%n,A%n) Output dense rank-2 array.","tags":"","loc":"interface/dense.html"},{"title":"matmul – SpecialMatrices","text":"public interface matmul This interface overloads the Fortran intrinsic matmul for the following types: Diagonal Bidiagonal Tridiagonal SymTridiagonal The intrinsic matmul is overloaded both for matrix-vector and matrix-matrix products.\nFor a matrix-matrix product , only the matrix has to be of the ones\nof the types defined by SpecialMatrices . Both and need to be standard \nFortran rank-2 arrays. All the underlying functions are defined as pure . Syntax For matrix-vector product with A being of a type defined by SpecialMatrices and x a standard rank-1 array: matmul ( A , x ) For matrix-matrix product with A being of a type defined by SpecialMatrices and B a rank-2 array: matmul ( A , B ) Functions private pure module function bidiag_multi_spmv(A, X) result(Y) Utility function to compute the matrix-matrix product where is of Bidiagonal type and X and Y are both rank-2 arrays. Arguments Type Intent Optional Attributes Name type( Bidiagonal ), intent(in) :: A Input matrix. real(kind=dp), intent(in) :: X (:,:) Input matrix (rank-2 array). Return Value real(kind=dp), (size(X,1),size(X,2)) Output matrix (rank-2 array). private pure module function bidiag_spmv(A, x) result(y) Utility function to compute the matrix-vector product where is of Bidiagonal type and x and y are both rank-1 arrays. Arguments Type Intent Optional Attributes Name type( Bidiagonal ), intent(in) :: A Input matrix. real(kind=dp), intent(in) :: x (:) Input vector. Return Value real(kind=dp), (size(x)) Output vector. private pure module function diag_multi_spmv(A, X) result(Y) Utility function to compute the matrix-vector product where is of Diagonal type and X and Y are both rank-2 arrays. Arguments Type Intent Optional Attributes Name type( Diagonal ), intent(in) :: A Input matrix. real(kind=dp), intent(in) :: X (:,:) Input matrix (rank-2 array). Return Value real(kind=dp), (size(X,1),size(X,2)) Output matrix (rank-2 array). private pure module function diag_spmv(A, x) result(y) Utility function to compute the matrix-vector product where is of Diagonal type and x and y are both rank-1 arrays. Arguments Type Intent Optional Attributes Name type( Diagonal ), intent(in) :: A Input matrix. real(kind=dp), intent(in) :: x (:) Input vector. Return Value real(kind=dp), (size(x)) Output vector. private pure module function symtridiag_multi_spmv(A, X) result(Y) Utility function to compute the matrix-matrix product where is of SymTridiagonal type and X and Y are both rank-2 arrays. Arguments Type Intent Optional Attributes Name type( SymTridiagonal ), intent(in) :: A real(kind=dp), intent(in) :: X (:,:) Return Value real(kind=dp), (size(X,1),size(X,2)) private pure module function symtridiag_spmv(A, x) result(y) Utility function to compute the matrix-vector product where is of SymTridiagonal type and x and y are both rank-1 arrays. Arguments Type Intent Optional Attributes Name type( SymTridiagonal ), intent(in) :: A Input matrix. real(kind=dp), intent(in) :: x (:) Input vector. Return Value real(kind=dp), (size(x)) Output vector. private pure module function tridiag_multi_spmv(A, X) result(Y) Utility function to compute the matrix-vector product where is of Tridiagonal type and X and Y are both rank-2 arrays. Arguments Type Intent Optional Attributes Name type( Tridiagonal ), intent(in) :: A Input matrix. real(kind=dp), intent(in) :: X (:,:) Input matrix (rank-2 array). Return Value real(kind=dp), (size(X,1),size(X,2)) Output matrix (rank-2 array). private pure module function tridiag_spmv(A, x) result(y) Utility function to compute the matrix-vector product where is of Tridiagonal type and x and y are both rank-1 arrays. Arguments Type Intent Optional Attributes Name type( Tridiagonal ), intent(in) :: A Input matrix. real(kind=dp), intent(in) :: x (:) Input vector. Return Value real(kind=dp), (size(x)) Output vector.","tags":"","loc":"interface/matmul.html"},{"title":"shape – SpecialMatrices","text":"public interface shape This interface provides methods to access the shape of a matrix of one of\nthe types defined by SpecialMatrices . Syntax shape ( A ) Functions private pure module function bidiag_shape(A) result(shape) Utility function to get the shape of a Bidiagonal matrix. Arguments Type Intent Optional Attributes Name type( Bidiagonal ), intent(in) :: A Input matrix. Return Value integer(kind=ilp), (2) Shape of the matrix. private pure module function diag_shape(A) result(shape) Utility function to get the shape of a Diagonal matrix. Arguments Type Intent Optional Attributes Name type( Diagonal ), intent(in) :: A Input matrix. Return Value integer(kind=ilp), (2) Shape of the matrix. private pure module function symtridiag_shape(A) result(shape) Utility function to get the shape of a SymTridiagonal matrix. Arguments Type Intent Optional Attributes Name type( SymTridiagonal ), intent(in) :: A Input matrix. Return Value integer(kind=ilp), (2) Shape of the matrix. private pure module function tridiag_shape(A) result(shape) Utility function to get the shape of a Tridiagonal matrix. Arguments Type Intent Optional Attributes Name type( Tridiagonal ), intent(in) :: A Input matrix. Return Value integer(kind=ilp), (2) Shape of the matrix.","tags":"","loc":"interface/shape.html"},{"title":"solve – SpecialMatrices","text":"public interface solve This interface overloads the solve interface from stdlib_linalg for solving a linear\nsystem where is of one of the types provided by SpecialMatrices .\nIt also enables to solve a linear system with multiple right-hand sides. Syntax To solve a system with being of one of the types defined by SpecialMatrices : y = solve ( A , x ) Arguments A :  Matrix of Diagonal , Bidiagonal , Tridiagonal or SymTridiagonal type.\n         It is an intent(in) argument. x :  Rank-1 or rank-2 array defining the right-hand side(s). It is an intent(in) argument. y :  Solution of the linear system. It has the same type and shape as x . Functions private pure module function bidiag_multi_solve(A, B) result(X) Utility function to solve a linear system with multiple right-hand sides where is of Bidiagonal type and B a rank-2 array. The solution X is also\na rank-2 array with the same type and dimensions as B . Arguments Type Intent Optional Attributes Name type( Bidiagonal ), intent(in) :: A Coefficient matrix. real(kind=dp), intent(in) :: B (:,:) Right-hand side vectors. Return Value real(kind=dp), (size(B,1),size(B,2)) Solution vectors. private pure module function bidiag_solve(A, b) result(x) Utility function to solve a linear system where is of Bidiagonal type and b a rank-1 array. The solution x is also a rank-1 array\nwith the same type and dimension as b . Arguments Type Intent Optional Attributes Name type( Bidiagonal ), intent(in) :: A Coefficient matrix. real(kind=dp), intent(in) :: b (:) Right-hand side vector. Return Value real(kind=dp), (size(b)) Solution vector. private pure module function diag_multi_solve(A, B) result(X) Utility function to solve a linear system with multiple right-hand sides where is of Diagonal type and B a rank-2 array. The solution X is also a\nrank-2 array with the same type and dimensions as B . Arguments Type Intent Optional Attributes Name type( Diagonal ), intent(in) :: A Coefficient matrix. real(kind=dp), intent(in) :: B (:,:) Right-hande side vectors. Return Value real(kind=dp), allocatable, (:,:) Solution vectors. private pure module function diag_solve(A, b) result(x) Utility function to solve the linear system where is of Diagonal type and b a rank-1 array. The solution x is also a rank-1 array\nwith the same type and dimension as b . Arguments Type Intent Optional Attributes Name type( Diagonal ), intent(in) :: A Coefficient matrix. real(kind=dp), intent(in) :: b (:) Right-hande side vector. Return Value real(kind=dp), allocatable, (:) Solution vector. private pure module function symtridiag_multi_solve(A, B) result(X) Utility function to solve a linear system with multiple right-hand side vectors\nwhere is of SymTridiagonal type and B a rank-2 array. The solution X is also a rank-2 array with the same type and dimensions as B . Arguments Type Intent Optional Attributes Name type( SymTridiagonal ), intent(in) :: A Coefficient matrix. real(kind=dp), intent(in) :: B (:,:) Right-hand side vectors. Return Value real(kind=dp), (size(B,1),size(B,2)) Solution vectors. private pure module function symtridiag_solve(A, b) result(x) Utility function to solve the linear system where is of SymTridiagonal type and b a rank-1 array. The solution x is also a rank-1\narray with the same type and dimension as b . Arguments Type Intent Optional Attributes Name type( SymTridiagonal ), intent(in) :: A Coefficient matrix. real(kind=dp), intent(in) :: b (:) Right-hande side vector. Return Value real(kind=dp), (size(b)) Solution vector. private pure module function tridiag_multi_solve(A, B) result(X) Utility function to solve a linear system with multiple right-hand sides where is of Tridiagonal type and B a rank-2 array. The solution X is also\na rank-2 array with the same type and dimensions as B . Arguments Type Intent Optional Attributes Name type( Tridiagonal ), intent(in) :: A Coefficient matrix. real(kind=dp), intent(in) :: B (:,:) Right-hand side vectors. Return Value real(kind=dp), (size(B,1),size(B,2)) Solution vectors. private pure module function tridiag_solve(A, b) result(x) Utility function to solve the linear system where is of Tridiagonal type and b a rank-1 array. The solution x is also a rank-1\narray with the same type and dimension as b . Arguments Type Intent Optional Attributes Name type( Tridiagonal ), intent(in) :: A Coefficient matrix. real(kind=dp), intent(in) :: b (:) Right-hand side vector. Return Value real(kind=dp), (size(b)) Solution vector.","tags":"","loc":"interface/solve.html"},{"title":"transpose – SpecialMatrices","text":"public interface transpose This interface overloads the Fortran intrinsic procedure to define the transpose\noperation for the various types defined in SpecialMatrices . Syntax B = transpose ( A ) Arguments A :  Matrix of Diagonal , Bidiagonal , Tridiagonal or SymTridiagonal type.\n         It is an intent(in) argument. B :  Resulting transposed matrix. It is of the same type as A . Functions private pure module function bidiag_transpose(A) result(B) Utility function to compute the transpose of a Bidiagonal matrix.\nThe output matrix is also of Bidiagonal type. Arguments Type Intent Optional Attributes Name type( Bidiagonal ), intent(in) :: A Input bidiagonal matrix. Return Value type( Bidiagonal ) Transpose of the original diagonal matrix. private pure module function diag_transpose(A) result(B) Utility function to compute the transpose of a Diagonal matrix.\nThe output matrix is also of Diagonal type. Arguments Type Intent Optional Attributes Name type( Diagonal ), intent(in) :: A Input Diagonal matrix. Return Value type( Diagonal ) Tranpose of the original diagonal matrix. private pure module function symtridiag_transpose(A) result(B) Utility function to compute the transpose of a SymTridiagonal matrix.\nThe output matrix is also of SymTridiagonal type. Arguments Type Intent Optional Attributes Name type( SymTridiagonal ), intent(in) :: A Input symmetric tridiagonal matrix. Return Value type( SymTridiagonal ) Transpose of the original matrix. private pure module function tridiag_transpose(A) result(B) Utility function to compute the tranpose of a Tridiagonal matrix.\nThe output matrix is also of Tridiagonal type. Arguments Type Intent Optional Attributes Name type( Tridiagonal ), intent(in) :: A Input tridiagonal matrix. Return Value type( Tridiagonal ) Transpose of the original tridiagonal matrix.","tags":"","loc":"interface/transpose.html"},{"title":"SpecialMatrices – SpecialMatrices","text":"Uses SpecialMatrices_Tridiagonal Subroutines public  subroutine say_hello () Arguments None","tags":"","loc":"module/specialmatrices.html"},{"title":"SpecialMatrices_Tridiagonal – SpecialMatrices","text":"Uses stdlib_linalg_constants stdlib_linalg_state Used by Descendants: BidiagonalMatrices DiagonalMatrices GenericTridiagonal SymmetricTridiagonal Interfaces public        interface Bidiagonal This interface provides different methods to construct a Bidiagonal matrix.\nOnly double precision is supported currently. Only the non-zero elements of are stored, i.e. Syntax Construct a Bidiagonal matrix filled with zeros: integer , parameter :: n = 100 type ( Bidiagonal ) :: A A = Bidiagonal ( n ) Construct a Bidiagonal matrix from rank-1 arrays: integer , parameter :: n real ( dp ), allocatable :: dv (:), ev (:) type ( Bidiagonal ) :: A integer :: i ev = [( i , i = 1 , n )]; dv = [( 2 * i , i = 1 , n )] A = Bidiagonal ( dv , ev , which = \"L\" ) Construct a Bidiagonal matrix with constant diagonals: integer , parameter :: n real ( dp ), parameter :: e = 1.0_dp , d = 2.0_dp type ( Bidiagonal ) :: A A = Bidiagonal ( d , e , n , which = \"L\" ) private pure module function construct_bidiag(dv, ev, which) result(A) Utility function to construct a Bidiagonal matrix from rank-1 arrays. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: dv (:) Diagonal elements of the matrix. real(kind=dp), intent(in) :: ev (:) Diagonal elements of the matrix. character(len=1), intent(in), optional :: which Whether A has a sub- or super-diagonal. Return Value type( Bidiagonal ) Corresponding bidiagonal matrix. private pure module function construct_constant_bidiag(d, e, n, which) result(A) Utility function to construct a Bidiagonal matrix with constant elements. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: d Constant diagonal elements. real(kind=dp), intent(in) :: e Constant diagonal elements. integer(kind=ilp), intent(in) :: n Dimension of the matrix. character(len=1), intent(in), optional :: which Whether A has a sub- or super-diagonal. Return Value type( Bidiagonal ) Corresponding bidiagonal matrix. private pure module function initialize_bidiag(n, which) result(A) Utility function to construct a Bidiagonal matrix filled with zeros. Arguments Type Intent Optional Attributes Name integer(kind=ilp), intent(in) :: n Dimension of the matrix. character(len=1), intent(in), optional :: which Whether A has a sub- or super-diagonal. Return Value type( Bidiagonal ) Corresponding bidiagonal matrix. public        interface Diagonal This interface provides different methods to construct a Diagonal matrix.\nOnly double precision is supported currently. Only the diagonal elements\nof are being stored, i.e. Syntax Construct a Diagonal matrix filled with zeros: integer , parameter :: n = 100 type ( Diagonal ) :: A A = Diagonal ( n ) Construct a Diagonal matrix from a vector. integer , parameter :: n = 100 real ( dp ), allocatable :: dv (:) type ( Diagonal ) :: A integer :: i dv = [( i , i = 1 , n )]; A = Diagonal ( dv ) Construct a Diagonal matrix with constant diagonal element. integer , parameter :: n = 100 real ( dp ), parameter :: d = 2.0_dp type ( Diagonal ) :: A A = Diagonal ( d , n ) Construct a Diagonal matrix from a standard Fortran rank-2 array. integer , parameter :: n = 100 real ( dp ) :: B ( n , n ) type ( Diagonal ) :: A call random_number ( B ); A = Diagonal ( B ) private pure module function construct_constant_diag(d, n) result(A) Utility function to construct a Diagonal matrix with constant diagonal element. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: d Constant diagonal element of the matrix. integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( Diagonal ) Corresponding diagonal matrix. private module function construct_dense_to_diag(A) result(B) Utility function to construct a Diagonal matrix from a rank-2 array. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: A (:,:) Dense [n x n] matrix from which to construct the Diagonal one. Return Value type( Diagonal ) Corresponding diagonal matrix. private pure module function construct_diag(dv) result(A) Utility function to construct a Diagonal matrix from a rank-1 array. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: dv (:) Diagonal elements of the matrix. Return Value type( Diagonal ) Corresponding diagonal matrix. private pure module function initialize_diag(n) result(A) Utility function to construct a Diagonal matrix filled with zeros. Arguments Type Intent Optional Attributes Name integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( Diagonal ) Corresponding diagonal matrix. public        interface SymTridiagonal This interface provides different methods to construct a SymTridiagonal matrix.\nOnly double precision is supported currently. Only the non-zero elements of are stored, i.e. Syntax Construct a SymTridiagonal matrix filled with zeros: integer , parameter :: n = 100 type ( SymTridiagonal ) :: A A = SymTridiagonal ( n ) Construct a SymTridiagonal matrix from rank-1 arrays: integer , parameter :: n real ( dp ), allocatable :: ev (:), dv (:) type ( SymTridiagonal ) :: A integer :: i dv = [( i , i = 1 , n )]; ev = [( 2 * i , i = 1 , n )] A = Tridiagonal ( dv , ev ) Construct a SymTridiagonal matrix with constant diagonals: integer , parameter :: n real ( dp ), parameter :: d = 1.0_dp , e = 2.0_dp type ( SymTridiagonal ) :: A A = SymTridiagonal ( d , e , n ) private pure module function construct_constant_symtridiag(d, e, n) result(A) Utility function to create a SymTridiagonal matrix with constant diagonal elements. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: d Constant diagonal elements of the matrix. real(kind=dp), intent(in) :: e Constant diagonal elements of the matrix. integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( SymTridiagonal ) Corresponding symmetric tridiagonal matrix. private pure module function construct_symtridiag(dv, ev) result(A) Utility function to create a SymTridiagonal matrix from rank-1 arrays. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: dv (:) Diagonal elements of the matrix. real(kind=dp), intent(in) :: ev (:) Diagonal elements of the matrix. Return Value type( SymTridiagonal ) Corresponding symmetric tridiagonal matrix. private pure module function initialize_symtridiag(n) result(A) Utility function to create a SymTridiagonal matrix filled with zeros. Arguments Type Intent Optional Attributes Name integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( SymTridiagonal ) Corresponding symmetric tridiagonal matrix. public        interface Tridiagonal This interface provides different methods to construct a Tridiagonal matrix.\nOnly double precision is supported currently. Only the non-zero elements of are stored, i.e. Syntax Construct a Tridiagonal matrix filled with zeros: integer , parameter :: n = 100 type ( Tridiagonal ) :: A A = Tridiagonal ( n ) Construct a Tridiagonal matrix from rank-1 arrays: integer , parameter :: n real ( dp ), allocatable :: dl (:), d (:), du (:) type ( Tridiagonal ) :: A integer :: i dl = [( i , i = 1 , n )]; d = [( 2 * i , i = 1 , n )]; dl = [( 3 * i , i = 1 , n )] A = Tridiagonal ( dl , d , du ) Construct a Tridiagonal matrix with constant diagonals: integer , parameter :: n real ( dp ), parameter :: dl = 1.0_dp , d = 2.0_dp , du = 3.0_dp type ( Tridiagonal ) :: A A = Tridiagonal ( dl , d , du , n ) Construct a Tridiagonal matrix from a standard Fortran rank-2 array: integer , parameter :: n = 100 real ( dp ) :: B ( n , n ) type ( Tridiagonal ) :: A call random_number ( B ); A = Tridiagonal ( B ) private pure module function construct_constant_tridiag(l, d, u, n) result(A) Utility function to construct a Tridiagonal matrix with constant elements. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: l Constant diagonal elements. real(kind=dp), intent(in) :: d Constant diagonal elements. real(kind=dp), intent(in) :: u Constant diagonal elements. integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( Tridiagonal ) Corresponding tridiagonal matrix. private module function construct_dense_to_tridiag(A) result(B) Utility function to construct a Tridiagonal matrix from a rank-2 array. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: A (:,:) Dense [n x n] matrix from which to construct the Tridiagonal one. Return Value type( Tridiagonal ) Corresponding tridiagonal matrix. private pure module function construct_tridiag(dl, d, du) result(A) Utility function to construct a Tridiagonal matrix from a set of rank-1 arrays. Arguments Type Intent Optional Attributes Name real(kind=dp), intent(in) :: dl (:) Diagonal elements of the matrix. real(kind=dp), intent(in) :: d (:) Diagonal elements of the matrix. real(kind=dp), intent(in) :: du (:) Diagonal elements of the matrix. Return Value type( Tridiagonal ) Corresponding tridiagonal matrix. private pure module function initialize_tridiag(n) result(A) Utility function to construct a Tridiagonal matrix filled with zeros. Arguments Type Intent Optional Attributes Name integer(kind=ilp), intent(in) :: n Dimension of the matrix. Return Value type( Tridiagonal ) Corresponding tridiagonal matrix. public        interface dense This interface provides methods to convert a matrix of one the types defined in SpecialMatrix to a regular rank-2 array. Syntax B = dense ( A ) Arguments A :  Matrix of Diagonal , Bidiagonal , Tridiagonal or SymTridiagonal type.\n         It is an intent(in) argument. B :  Rank-2 array representation of the matrix . private pure module function bidiag_to_dense(A) result(B) Utility function to convert a Bidiagonal matrix to a regular rank-2 array. Arguments Type Intent Optional Attributes Name type( Bidiagonal ), intent(in) :: A Input bidiagonal matrix. Return Value real(kind=dp), (A%n,A%n) Output dense rank-2 array. private pure module function diag_to_dense(A) result(B) Utility function to convert a Diagonal matrix to a regular rank-2 array. Arguments Type Intent Optional Attributes Name type( Diagonal ), intent(in) :: A Input diagonal matrix. Return Value real(kind=dp), (A%n,A%n) Output dense rank-2 array. private pure module function symtridiag_to_dense(A) result(B) Utility function to convert a SymTridiagonal matrix to a regular rank-2 array. Arguments Type Intent Optional Attributes Name type( SymTridiagonal ), intent(in) :: A Input symmetric tridiagonal matrix. Return Value real(kind=dp), (A%n,A%n) Output dense rank-2 array. private pure module function tridiag_to_dense(A) result(B) Utility function to convert a Tridiagonal matrix to a regular rank-2 array. Arguments Type Intent Optional Attributes Name type( Tridiagonal ), intent(in) :: A Input tridiagonal matrix. Return Value real(kind=dp), (A%n,A%n) Output dense rank-2 array. public        interface matmul This interface overloads the Fortran intrinsic matmul for the following types: Diagonal Bidiagonal Tridiagonal SymTridiagonal The intrinsic matmul is overloaded both for matrix-vector and matrix-matrix products.\nFor a matrix-matrix product , only the matrix has to be of the ones\nof the types defined by SpecialMatrices . Both and need to be standard \nFortran rank-2 arrays. All the underlying functions are defined as pure . Syntax For matrix-vector product with A being of a type defined by SpecialMatrices and x a standard rank-1 array: matmul ( A , x ) For matrix-matrix product with A being of a type defined by SpecialMatrices and B a rank-2 array: matmul ( A , B ) private pure module function bidiag_multi_spmv(A, X) result(Y) Utility function to compute the matrix-matrix product where is of Bidiagonal type and X and Y are both rank-2 arrays. Arguments Type Intent Optional Attributes Name type( Bidiagonal ), intent(in) :: A Input matrix. real(kind=dp), intent(in) :: X (:,:) Input matrix (rank-2 array). Return Value real(kind=dp), (size(X,1),size(X,2)) Output matrix (rank-2 array). private pure module function bidiag_spmv(A, x) result(y) Utility function to compute the matrix-vector product where is of Bidiagonal type and x and y are both rank-1 arrays. Arguments Type Intent Optional Attributes Name type( Bidiagonal ), intent(in) :: A Input matrix. real(kind=dp), intent(in) :: x (:) Input vector. Return Value real(kind=dp), (size(x)) Output vector. private pure module function diag_multi_spmv(A, X) result(Y) Utility function to compute the matrix-vector product where is of Diagonal type and X and Y are both rank-2 arrays. Arguments Type Intent Optional Attributes Name type( Diagonal ), intent(in) :: A Input matrix. real(kind=dp), intent(in) :: X (:,:) Input matrix (rank-2 array). Return Value real(kind=dp), (size(X,1),size(X,2)) Output matrix (rank-2 array). private pure module function diag_spmv(A, x) result(y) Utility function to compute the matrix-vector product where is of Diagonal type and x and y are both rank-1 arrays. Arguments Type Intent Optional Attributes Name type( Diagonal ), intent(in) :: A Input matrix. real(kind=dp), intent(in) :: x (:) Input vector. Return Value real(kind=dp), (size(x)) Output vector. private pure module function symtridiag_multi_spmv(A, X) result(Y) Utility function to compute the matrix-matrix product where is of SymTridiagonal type and X and Y are both rank-2 arrays. Arguments Type Intent Optional Attributes Name type( SymTridiagonal ), intent(in) :: A real(kind=dp), intent(in) :: X (:,:) Return Value real(kind=dp), (size(X,1),size(X,2)) private pure module function symtridiag_spmv(A, x) result(y) Utility function to compute the matrix-vector product where is of SymTridiagonal type and x and y are both rank-1 arrays. Arguments Type Intent Optional Attributes Name type( SymTridiagonal ), intent(in) :: A Input matrix. real(kind=dp), intent(in) :: x (:) Input vector. Return Value real(kind=dp), (size(x)) Output vector. private pure module function tridiag_multi_spmv(A, X) result(Y) Utility function to compute the matrix-vector product where is of Tridiagonal type and X and Y are both rank-2 arrays. Arguments Type Intent Optional Attributes Name type( Tridiagonal ), intent(in) :: A Input matrix. real(kind=dp), intent(in) :: X (:,:) Input matrix (rank-2 array). Return Value real(kind=dp), (size(X,1),size(X,2)) Output matrix (rank-2 array). private pure module function tridiag_spmv(A, x) result(y) Utility function to compute the matrix-vector product where is of Tridiagonal type and x and y are both rank-1 arrays. Arguments Type Intent Optional Attributes Name type( Tridiagonal ), intent(in) :: A Input matrix. real(kind=dp), intent(in) :: x (:) Input vector. Return Value real(kind=dp), (size(x)) Output vector. public        interface shape This interface provides methods to access the shape of a matrix of one of\nthe types defined by SpecialMatrices . Syntax shape ( A ) private pure module function bidiag_shape(A) result(shape) Utility function to get the shape of a Bidiagonal matrix. Arguments Type Intent Optional Attributes Name type( Bidiagonal ), intent(in) :: A Input matrix. Return Value integer(kind=ilp), (2) Shape of the matrix. private pure module function diag_shape(A) result(shape) Utility function to get the shape of a Diagonal matrix. Arguments Type Intent Optional Attributes Name type( Diagonal ), intent(in) :: A Input matrix. Return Value integer(kind=ilp), (2) Shape of the matrix. private pure module function symtridiag_shape(A) result(shape) Utility function to get the shape of a SymTridiagonal matrix. Arguments Type Intent Optional Attributes Name type( SymTridiagonal ), intent(in) :: A Input matrix. Return Value integer(kind=ilp), (2) Shape of the matrix. private pure module function tridiag_shape(A) result(shape) Utility function to get the shape of a Tridiagonal matrix. Arguments Type Intent Optional Attributes Name type( Tridiagonal ), intent(in) :: A Input matrix. Return Value integer(kind=ilp), (2) Shape of the matrix. public        interface solve This interface overloads the solve interface from stdlib_linalg for solving a linear\nsystem where is of one of the types provided by SpecialMatrices .\nIt also enables to solve a linear system with multiple right-hand sides. Syntax To solve a system with being of one of the types defined by SpecialMatrices : y = solve ( A , x ) Arguments A :  Matrix of Diagonal , Bidiagonal , Tridiagonal or SymTridiagonal type.\n         It is an intent(in) argument. x :  Rank-1 or rank-2 array defining the right-hand side(s). It is an intent(in) argument. y :  Solution of the linear system. It has the same type and shape as x . private pure module function bidiag_multi_solve(A, B) result(X) Utility function to solve a linear system with multiple right-hand sides where is of Bidiagonal type and B a rank-2 array. The solution X is also\na rank-2 array with the same type and dimensions as B . Arguments Type Intent Optional Attributes Name type( Bidiagonal ), intent(in) :: A Coefficient matrix. real(kind=dp), intent(in) :: B (:,:) Right-hand side vectors. Return Value real(kind=dp), (size(B,1),size(B,2)) Solution vectors. private pure module function bidiag_solve(A, b) result(x) Utility function to solve a linear system where is of Bidiagonal type and b a rank-1 array. The solution x is also a rank-1 array\nwith the same type and dimension as b . Arguments Type Intent Optional Attributes Name type( Bidiagonal ), intent(in) :: A Coefficient matrix. real(kind=dp), intent(in) :: b (:) Right-hand side vector. Return Value real(kind=dp), (size(b)) Solution vector. private pure module function diag_multi_solve(A, B) result(X) Utility function to solve a linear system with multiple right-hand sides where is of Diagonal type and B a rank-2 array. The solution X is also a\nrank-2 array with the same type and dimensions as B . Arguments Type Intent Optional Attributes Name type( Diagonal ), intent(in) :: A Coefficient matrix. real(kind=dp), intent(in) :: B (:,:) Right-hande side vectors. Return Value real(kind=dp), allocatable, (:,:) Solution vectors. private pure module function diag_solve(A, b) result(x) Utility function to solve the linear system where is of Diagonal type and b a rank-1 array. The solution x is also a rank-1 array\nwith the same type and dimension as b . Arguments Type Intent Optional Attributes Name type( Diagonal ), intent(in) :: A Coefficient matrix. real(kind=dp), intent(in) :: b (:) Right-hande side vector. Return Value real(kind=dp), allocatable, (:) Solution vector. private pure module function symtridiag_multi_solve(A, B) result(X) Utility function to solve a linear system with multiple right-hand side vectors\nwhere is of SymTridiagonal type and B a rank-2 array. The solution X is also a rank-2 array with the same type and dimensions as B . Arguments Type Intent Optional Attributes Name type( SymTridiagonal ), intent(in) :: A Coefficient matrix. real(kind=dp), intent(in) :: B (:,:) Right-hand side vectors. Return Value real(kind=dp), (size(B,1),size(B,2)) Solution vectors. private pure module function symtridiag_solve(A, b) result(x) Utility function to solve the linear system where is of SymTridiagonal type and b a rank-1 array. The solution x is also a rank-1\narray with the same type and dimension as b . Arguments Type Intent Optional Attributes Name type( SymTridiagonal ), intent(in) :: A Coefficient matrix. real(kind=dp), intent(in) :: b (:) Right-hande side vector. Return Value real(kind=dp), (size(b)) Solution vector. private pure module function tridiag_multi_solve(A, B) result(X) Utility function to solve a linear system with multiple right-hand sides where is of Tridiagonal type and B a rank-2 array. The solution X is also\na rank-2 array with the same type and dimensions as B . Arguments Type Intent Optional Attributes Name type( Tridiagonal ), intent(in) :: A Coefficient matrix. real(kind=dp), intent(in) :: B (:,:) Right-hand side vectors. Return Value real(kind=dp), (size(B,1),size(B,2)) Solution vectors. private pure module function tridiag_solve(A, b) result(x) Utility function to solve the linear system where is of Tridiagonal type and b a rank-1 array. The solution x is also a rank-1\narray with the same type and dimension as b . Arguments Type Intent Optional Attributes Name type( Tridiagonal ), intent(in) :: A Coefficient matrix. real(kind=dp), intent(in) :: b (:) Right-hand side vector. Return Value real(kind=dp), (size(b)) Solution vector. public        interface transpose This interface overloads the Fortran intrinsic procedure to define the transpose\noperation for the various types defined in SpecialMatrices . Syntax B = transpose ( A ) Arguments A :  Matrix of Diagonal , Bidiagonal , Tridiagonal or SymTridiagonal type.\n         It is an intent(in) argument. B :  Resulting transposed matrix. It is of the same type as A . private pure module function bidiag_transpose(A) result(B) Utility function to compute the transpose of a Bidiagonal matrix.\nThe output matrix is also of Bidiagonal type. Arguments Type Intent Optional Attributes Name type( Bidiagonal ), intent(in) :: A Input bidiagonal matrix. Return Value type( Bidiagonal ) Transpose of the original diagonal matrix. private pure module function diag_transpose(A) result(B) Utility function to compute the transpose of a Diagonal matrix.\nThe output matrix is also of Diagonal type. Arguments Type Intent Optional Attributes Name type( Diagonal ), intent(in) :: A Input Diagonal matrix. Return Value type( Diagonal ) Tranpose of the original diagonal matrix. private pure module function symtridiag_transpose(A) result(B) Utility function to compute the transpose of a SymTridiagonal matrix.\nThe output matrix is also of SymTridiagonal type. Arguments Type Intent Optional Attributes Name type( SymTridiagonal ), intent(in) :: A Input symmetric tridiagonal matrix. Return Value type( SymTridiagonal ) Transpose of the original matrix. private pure module function tridiag_transpose(A) result(B) Utility function to compute the tranpose of a Tridiagonal matrix.\nThe output matrix is also of Tridiagonal type. Arguments Type Intent Optional Attributes Name type( Tridiagonal ), intent(in) :: A Input tridiagonal matrix. Return Value type( Tridiagonal ) Transpose of the original tridiagonal matrix. Derived Types type, public :: Bidiagonal Base type used to define a Bidiagonal matrix of size [n x n] with diagonals given by\nthe rank-1 arrays dv and ev . The character which determines whether ev defines the\nsub-diagonal ( which = \"L\" , default) or the super-diagonal ( which = \"U\" ). Components Type Visibility Attributes Name Initial real(kind=dp), public, allocatable :: dv (:) Diagonal elements real(kind=dp), public, allocatable :: ev (:) Diagonal elements integer(kind=ilp), public :: n Dimension of the matrix. character(len=1), public :: which Whether it is lower- or upper-bidiagonal. Constructor This interface provides different methods to construct a Bidiagonal matrix.\nOnly double precision is supported currently. Only the non-zero elements of are stored, i.e. Read more… private\n\n                    pure, module\n                    function construct_bidiag (dv, ev, which) Utility function to construct a Bidiagonal matrix from rank-1 arrays. private\n\n                    pure, module\n                    function construct_constant_bidiag (d, e, n, which) Utility function to construct a Bidiagonal matrix with constant elements. private\n\n                    pure, module\n                    function initialize_bidiag (n, which) Utility function to construct a Bidiagonal matrix filled with zeros. type, public :: Diagonal Base type used to define a Diagonal matrix of size [n x n] with diagonal given by the\nrank-1 array dv . Components Type Visibility Attributes Name Initial real(kind=dp), public, allocatable :: dv (:) Diagonal elements of the matrix. integer(kind=ilp), public :: n Dimension of the matrix. Constructor This interface provides different methods to construct a Diagonal matrix.\nOnly double precision is supported currently. Only the diagonal elements\nof are being stored, i.e. Read more… private\n\n                    pure, module\n                    function construct_constant_diag (d, n) Utility function to construct a Diagonal matrix with constant diagonal element. private\n\n                    module\n                    function construct_dense_to_diag (A) Utility function to construct a Diagonal matrix from a rank-2 array. private\n\n                    pure, module\n                    function construct_diag (dv) Utility function to construct a Diagonal matrix from a rank-1 array. private\n\n                    pure, module\n                    function initialize_diag (n) Utility function to construct a Diagonal matrix filled with zeros. type, public :: SymTridiagonal Base type used to define a SymTridiagonal matrix of size [n x n] with diagonal elements\ngiven by the rank-1 arrays dv (diagonal) and ev (sub- and super-diagonal). Components Type Visibility Attributes Name Initial real(kind=dp), public, allocatable :: dv (:) Tridiagonal elements. real(kind=dp), public, allocatable :: ev (:) Tridiagonal elements. integer(kind=ilp), public :: n Dimension of the matrix. Constructor This interface provides different methods to construct a SymTridiagonal matrix.\nOnly double precision is supported currently. Only the non-zero elements of are stored, i.e. Read more… private\n\n                    pure, module\n                    function construct_constant_symtridiag (d, e, n) Utility function to create a SymTridiagonal matrix with constant diagonal elements. private\n\n                    pure, module\n                    function construct_symtridiag (dv, ev) Utility function to create a SymTridiagonal matrix from rank-1 arrays. private\n\n                    pure, module\n                    function initialize_symtridiag (n) Utility function to create a SymTridiagonal matrix filled with zeros. type, public :: Tridiagonal Base type used to define a Tridiagonal matrix of size [n x n] with diagonal elements\ngiven by the rank-1 arrays dl (sub-diagonal), d (diagonal) and du (super-diagonal). Components Type Visibility Attributes Name Initial real(kind=dp), public, allocatable :: d (:) Tridiagonal elements. real(kind=dp), public, allocatable :: dl (:) Tridiagonal elements. real(kind=dp), public, allocatable :: du (:) Tridiagonal elements. integer(kind=ilp), public :: n Dimension of the matrix. Constructor This interface provides different methods to construct a Tridiagonal matrix.\nOnly double precision is supported currently. Only the non-zero elements of are stored, i.e. Read more… private\n\n                    pure, module\n                    function construct_constant_tridiag (l, d, u, n) Utility function to construct a Tridiagonal matrix with constant elements. private\n\n                    module\n                    function construct_dense_to_tridiag (A) Utility function to construct a Tridiagonal matrix from a rank-2 array. private\n\n                    pure, module\n                    function construct_tridiag (dl, d, du) Utility function to construct a Tridiagonal matrix from a set of rank-1 arrays. private\n\n                    pure, module\n                    function initialize_tridiag (n) Utility function to construct a Tridiagonal matrix filled with zeros.","tags":"","loc":"module/specialmatrices_tridiagonal.html"},{"title":"SymmetricTridiagonal – SpecialMatrices","text":"Uses stdlib_linalg_lapack Ancestors: SpecialMatrices_Tridiagonal","tags":"","loc":"module/symmetrictridiagonal.html"},{"title":"GenericTridiagonal – SpecialMatrices","text":"Uses stdlib_linalg_lapack stdlib_linalg Ancestors: SpecialMatrices_Tridiagonal","tags":"","loc":"module/generictridiagonal.html"},{"title":"DiagonalMatrices – SpecialMatrices","text":"Uses stdlib_linalg stdlib_linalg_state Ancestors: SpecialMatrices_Tridiagonal","tags":"","loc":"module/diagonalmatrices.html"},{"title":"BidiagonalMatrices – SpecialMatrices","text":"Uses stdlib_optval stdlib_linalg_lapack Ancestors: SpecialMatrices_Tridiagonal","tags":"","loc":"module/bidiagonalmatrices.html"},{"title":"specialmatrices_symtridiagonal.f90 – SpecialMatrices","text":"Source Code submodule ( SpecialMatrices_Tridiagonal ) SymmetricTridiagonal use stdlib_linalg_lapack , only : gtsv implicit none ( type , external ) contains !-------------------------------- !-----     Constructors     ----- !-------------------------------- pure module function initialize_symtridiag ( n ) result ( A ) !! Utility function to create a `SymTridiagonal` matrix filled with zeros. integer ( ilp ), intent ( in ) :: n !! Dimension of the matrix. type ( SymTridiagonal ) :: A !! Corresponding symmetric tridiagonal matrix. A % n = n ; allocate ( A % dv ( n ), A % ev ( n - 1 )) A % dv = 0.0_dp ; A % ev = 0.0_dp return end function initialize_symtridiag pure module function construct_symtridiag ( dv , ev ) result ( A ) !! Utility function to create a `SymTridiagonal` matrix from rank-1 arrays. real ( dp ), intent ( in ) :: dv (:), ev (:) !! Diagonal elements of the matrix. type ( SymTridiagonal ) :: A !! Corresponding symmetric tridiagonal matrix. A % n = size ( dv ); A % dv = dv ; A % ev = ev return end function construct_symtridiag pure module function construct_constant_symtridiag ( d , e , n ) result ( A ) !! Utility function to create a `SymTridiagonal` matrix with constant diagonal elements. real ( dp ), intent ( in ) :: d , e !! Constant diagonal elements of the matrix. integer ( ilp ), intent ( in ) :: n !! Dimension of the matrix. type ( SymTridiagonal ) :: A !! Corresponding symmetric tridiagonal matrix. integer i A % n = n ; A % dv = [( d , i = 1 , n )]; A % ev = [( e , i = 1 , n - 1 )] return end function construct_constant_symtridiag !------------------------------------------------------------ !-----     Matrix-vector and Matrix-matrix products     ----- !------------------------------------------------------------ pure module function symtridiag_spmv ( A , x ) result ( y ) !! Utility function to compute the matrix-vector product where  A  is of !! `SymTridiagonal` type and `x` and `y` are both rank-1 arrays. type ( SymTridiagonal ), intent ( in ) :: A !! Input matrix. real ( dp ), intent ( in ) :: x (:) !! Input vector. real ( dp ) :: y ( size ( x )) !! Output vector. integer :: i , n n = size ( x ); y ( 1 ) = A % dv ( 1 ) * x ( 1 ) + A % ev ( 1 ) * x ( 2 ) do concurrent ( i = 2 : n - 1 ) y ( i ) = A % ev ( i - 1 ) * x ( i - 1 ) + A % dv ( i ) * x ( i ) + A % ev ( i ) * x ( i + 1 ) enddo y ( n ) = A % dv ( n ) * x ( n ) + A % ev ( n - 1 ) * x ( n - 1 ) return end function symtridiag_spmv pure module function symtridiag_multi_spmv ( A , X ) result ( Y ) !! Utility function to compute matrix-matrix product where  A  is of !! `SymTridiagonal` type and `X` and `Y` are both rank-2 arrays. type ( SymTridiagonal ), intent ( in ) :: A !! Input matrix. real ( dp ), intent ( in ) :: X (:, :) !! Input matrix (rank-2 array). real ( dp ) :: Y ( size ( X , 1 ), size ( X , 2 )) !! Output matrix (rank-2 array). integer ( ilp ) :: i do concurrent ( i = 1 : size ( X , 2 )) Y (:, i ) = symtridiag_spmv ( A , X (:, i )) enddo end function symtridiag_multi_spmv !---------------------------------- !-----     Linear Algebra     ----- !---------------------------------- pure module function symtridiag_solve ( A , b ) result ( x ) !! Utility function to solve a linear system  Ax = b  where  A  is of !! `SymTridiagonal` type and `b` a rank-1 array. The solution `x` is also a rank-1 array !! with the same type and dimension as `b`. type ( SymTridiagonal ), intent ( in ) :: A !! Coefficient matrix. real ( dp ), intent ( in ) :: b (:) !! Right-hand side vector. real ( dp ) :: x ( size ( b )) !! Solution vector. integer :: i , n , nrhs , info real ( dp ) :: dl ( A % n - 1 ), d ( A % n ), du ( A % n - 1 ), b_ ( A % n , 1 ) ! Initialize arrays. n = A % n ; dl = A % ev ; d = A % dv ; du = A % ev ; b_ (:, 1 ) = b ; nrhs = 1 ! Solve the system. call gtsv ( n , nrhs , dl , d , du , b_ , n , info ) ! Return the solution. x = b_ (:, 1 ) return end function symtridiag_solve pure module function symtridiag_multi_solve ( A , B ) result ( X ) !! Utility function to solve a linear system with multiple right-hand sides where  A  !! is of `SymTridiagonal` type and `B` a rank-2 array. The solution `X` is also a rank-2 !! array with the same type and dimension as `B`. type ( SymTridiagonal ), intent ( in ) :: A !! Coefficient matrix. real ( dp ), intent ( in ) :: B (:, :) !! Right-hand side vectors. real ( dp ) :: X ( size ( B , 1 ), size ( B , 2 )) !! Solution vectors. integer :: i , n , nrhs , info real ( dp ) :: dl ( A % n - 1 ), d ( A % n ), du ( A % n - 1 ) ! Initialize arrays. n = A % n ; dl = A % ev ; d = A % dv ; du = A % ev ; nrhs = size ( B , 2 ); X = B ! Solve the systems. call gtsv ( n , nrhs , dl , d , du , X , n , info ) end function symtridiag_multi_solve !------------------------------------- !-----     Utility functions     ----- !------------------------------------- pure module function symtridiag_to_dense ( A ) result ( B ) !! Utility function to convert a `SymTridiagonal` matrix to a regular rank-2 array. type ( SymTridiagonal ), intent ( in ) :: A !! Input symmetric tridiagonal matrix. real ( dp ) :: B ( A % n , A % n ) !! Output dense rank-2 array. integer :: i , n n = A % n ; B = 0.0_dp B ( 1 , 1 ) = A % dv ( 1 ); B ( 1 , 2 ) = A % ev ( 1 ) do concurrent ( i = 2 : n - 1 ) B ( i , i - 1 ) = A % ev ( i - 1 ) B ( i , i ) = A % dv ( i ) B ( i , i + 1 ) = A % ev ( i ) end do B ( n , n - 1 ) = A % ev ( n - 1 ); B ( n , n ) = A % dv ( n ) return end function symtridiag_to_dense pure module function symtridiag_transpose ( A ) result ( B ) !! Utility function to compute the transpose of a `SymTridiagonal` matrix. !! The output matrix is also of `SymTridiagonal` type. type ( SymTridiagonal ), intent ( in ) :: A !! Input symmetric tridiagonal matrix. type ( SymTridiagonal ) :: B !! Transpose of the original matrix. B = A return end function symtridiag_transpose pure module function symtridiag_shape ( A ) result ( shape ) type ( SymTridiagonal ), intent ( in ) :: A !! Input matrix. integer ( ilp ) :: shape ( 2 ) !! Shape of the matrix. shape ( 2 ) = A % n return end function symtridiag_shape end submodule SymmetricTridiagonal","tags":"","loc":"sourcefile/specialmatrices_symtridiagonal.f90.html"},{"title":"specialmatrices_tridiagonal_generic.f90 – SpecialMatrices","text":"Source Code submodule ( SpecialMatrices_Tridiagonal ) GenericTridiagonal use stdlib_linalg , only : diag use stdlib_linalg_lapack , only : gtsv implicit none ( type , external ) contains !-------------------------------- !-----     Constructors     ----- !-------------------------------- pure module function initialize_tridiag ( n ) result ( A ) !! Utility function to construct a `Tridiagonal` matrix filled with zeros. integer ( ilp ), intent ( in ) :: n !! Dimension of the matrix. type ( Tridiagonal ) :: A !! Corresponding tridiagonal matrix. A % n = n ; allocate ( A % d ( n ), A % du ( n - 1 ), A % dl ( n - 1 )) A % d = 0.0_dp ; A % du = 0.0_dp ; A % dl = 0.0_dp return end function initialize_tridiag pure module function construct_tridiag ( dl , d , du ) result ( A ) !! Utility function to construct a `Tridiagonal` matrix from rank-1 arrays. real ( dp ), intent ( in ) :: dl (:), d (:), du (:) !! Diagonal elements of the matrix. type ( Tridiagonal ) :: A !! Corresponding tridiagonal matrix. A % n = size ( d ); A % dl = dl ; A % d = d ; A % du = du return end function construct_tridiag pure module function construct_constant_tridiag ( l , d , u , n ) result ( A ) !! Utility function to construct a `Tridiagonal` matrix with constant diagonals. real ( dp ), intent ( in ) :: l , d , u !! Constant diagonal elements of the matrix. integer ( ilp ), intent ( in ) :: n !! Dimension of the matrix. type ( Tridiagonal ) :: A !! Corresponding tridiagonal matrix. integer ( ilp ) :: i A % n = n ; A % dl = [( l , i = 1 , n - 1 )]; A % d = [( d , i = 1 , n )]; A % du = [( u , i = 1 , n - 1 )] end function construct_constant_tridiag module function construct_dense_to_tridiag ( A ) result ( B ) !! Utility function to construct a `Tridiagonal` matrix from a rank-2 array. real ( dp ), intent ( in ) :: A (:, :) !! Dense [n x n] matrix from which to construct the `Tridiagonal` one. type ( Tridiagonal ) :: B !! Corresponding tridiagonal matrix. B = Tridiagonal ( diag ( A , - 1 ), diag ( A ), diag ( A , 1 )) return end function construct_dense_to_tridiag !------------------------------------------------------------ !-----     Matrix-vector and Matrix-matrix products     ----- !------------------------------------------------------------ pure module function tridiag_spmv ( A , x ) result ( y ) !! Utility function to compute the matrix-vector product  y = Ax  where  A  !! is of `Tridiagonal` type and `x` and `y` are both rank-1 arrays. type ( Tridiagonal ), intent ( in ) :: A !! Input matrix. real ( dp ), intent ( in ) :: x (:) !! Input vector. real ( dp ) :: y ( size ( x )) !! Output vector. integer :: i , n n = size ( x ); y ( 1 ) = A % d ( 1 ) * x ( 1 ) + A % du ( 1 ) * x ( 2 ) do concurrent ( i = 2 : n - 1 ) y ( i ) = A % dl ( i - 1 ) * x ( i - 1 ) + A % d ( i ) * x ( i ) + A % du ( i ) * x ( i + 1 ) end do y ( n ) = A % d ( n ) * x ( n ) + A % dl ( n - 1 ) * x ( n - 1 ) return end function tridiag_spmv pure module function tridiag_multi_spmv ( A , X ) result ( Y ) !! Utility function to compute the matrix-matrix product  Y = AX  where  A  !!  is of `Tridiagonal` type and `X` and `Y` are both rank-2 arrays. type ( Tridiagonal ), intent ( in ) :: A !! Input matrix. real ( dp ), intent ( in ) :: X (:, :) !! Input matrix (rank-2 array). real ( dp ) :: Y ( size ( X , 1 ), size ( X , 2 )) !! Output matrix (rank-2 array). integer ( ilp ) :: i do concurrent ( i = 1 : size ( X , 2 )) Y (:, i ) = tridiag_spmv ( A , X (:, i )) end do return end function tridiag_multi_spmv !---------------------------------- !-----     Linear Algebra     ----- !---------------------------------- pure module function tridiag_solve ( A , b ) result ( x ) !! Utility function to solve the linear system  Ax = b  where  A  is of !! `Tridiagonal` type and `b` a rank-1 array. The solution `x` is also a rank-1 array !! with the same type and dimension as `b`. type ( Tridiagonal ), intent ( in ) :: A !! Coefficient matrix. real ( dp ), intent ( in ) :: b (:) !! Right-hand side vector. real ( dp ) :: x ( size ( b )) !! Solution vector. integer :: i , n , nrhs , info real ( dp ) :: dl ( A % n - 1 ), d ( A % n ), du ( A % n - 1 ), b_ ( A % n , 1 ) ! Initialize arrays. n = A % n ; dl = A % dl ; d = A % d ; du = A % du ; b_ (:, 1 ) = b ; nrhs = 1 ! Solve the system. call gtsv ( n , nrhs , dl , d , du , b_ , n , info ) ! Return the solution. x = b_ (:, 1 ) return end function tridiag_solve pure module function tridiag_multi_solve ( A , B ) result ( X ) !! Utility function to solve a linear system with multiple right-hand sides where !!  A  is of `Tridiagonal` type and `B` a rank-2 array. The solution `X` is also !! a rank-2 array with the same type and dimensions as `B`. type ( Tridiagonal ), intent ( in ) :: A real ( dp ), intent ( in ) :: B (:, :) real ( dp ) :: X ( size ( B , 1 ), size ( B , 2 )) integer :: i , n , nrhs , info real ( dp ) :: dl ( A % n - 1 ), d ( A % n ), du ( A % n - 1 ) ! Initialize arrays. n = A % n ; dl = A % dl ; d = A % d ; du = A % du ; nrhs = size ( B , 2 ); X = B ! Solve the systems. call gtsv ( n , nrhs , dl , d , du , X , n , info ) end function tridiag_multi_solve !------------------------------------- !-----     Utility functions     ----- !------------------------------------- pure module function tridiag_shape ( A ) result ( shape ) type ( Tridiagonal ), intent ( in ) :: A !! Input matrix. integer ( ilp ) :: shape ( 2 ) !! Shape of the matrix. shape = A % n return end function tridiag_shape pure module function tridiag_to_dense ( A ) result ( B ) !! Utility function to convert a `Tridiagonal` matrix to a regular rank-2 array. type ( Tridiagonal ), intent ( in ) :: A !! Input tridiagonal matrix. real ( dp ) :: B ( A % n , A % n ) !! Output dense rank-2 array. integer :: i , n n = A % n ; B = 0.0_dp B ( 1 , 1 ) = A % d ( 1 ); B ( 1 , 2 ) = A % du ( 1 ) do concurrent ( i = 2 : n - 1 ) B ( i , i - 1 ) = A % dl ( i - 1 ) B ( i , i ) = A % d ( i ) B ( i , i + 1 ) = A % du ( i ) end do B ( n , n - 1 ) = A % dl ( n - 1 ); B ( n , n ) = A % d ( n ) return end function tridiag_to_dense pure module function tridiag_transpose ( A ) result ( B ) !! Utility function to compute the transpose of a `Tridiagonal` matrix. !! The output matrix is also of `Tridiagonal` type. type ( Tridiagonal ), intent ( in ) :: A !! Input tridiagonal matrix. type ( Tridiagonal ) :: B !! Transpose of the original tridiagonal matrix. B = A ; B % dl = A % du ; B % du = A % dl end function tridiag_transpose end submodule GenericTridiagonal","tags":"","loc":"sourcefile/specialmatrices_tridiagonal_generic.f90.html"},{"title":"SpecialMatrices.f90 – SpecialMatrices","text":"Source Code module SpecialMatrices use SpecialMatrices_Tridiagonal implicit none private !-------------------------------- !-----     Matrix types     ----- !-------------------------------- public :: Diagonal public :: Bidiagonal public :: Tridiagonal public :: SymTridiagonal !---------------------------------- !-----     Linear Algebra     ----- !---------------------------------- public :: transpose public :: matmul public :: solve !------------------------------------- !-----     Utility functions     ----- !------------------------------------- public :: dense public :: shape public :: say_hello contains subroutine say_hello print * , \"Hello, SpecialMatrices!\" end subroutine say_hello end module SpecialMatrices","tags":"","loc":"sourcefile/specialmatrices.f90.html"},{"title":"specialmatrices_diagonal.f90 – SpecialMatrices","text":"Source Code submodule ( SpecialMatrices_Tridiagonal ) DiagonalMatrices use stdlib_linalg , only : eye , diag use stdlib_linalg_state , only : linalg_state_type , linalg_error_handling , LINALG_VALUE_ERROR , & LINALG_INTERNAL_ERROR , LINALG_VALUE_ERROR implicit none ( type , external ) contains !-------------------------------- !-----     Constructors     ----- !-------------------------------- pure module function initialize_diag ( n ) result ( A ) !! Utility function to construct a `Diagonal` matrix filled with zeros. integer ( ilp ), intent ( in ) :: n !! Dimension of the matrix. type ( Diagonal ) :: A !! Corresponding diagonal matrix. A % n = n ; allocate ( A % dv ( n )); A % dv = 0.0_dp return end function initialize_diag pure module function construct_diag ( dv ) result ( A ) !! Utility function to construct a `Diagonal` matrix from a rank-1 array. real ( dp ), intent ( in ) :: dv (:) !! Diagonal element of the matrix. type ( Diagonal ) :: A !! Corresponding diagonal matrix. A % n = size ( dv ); A % dv = dv return end function construct_diag pure module function construct_constant_diag ( d , n ) result ( A ) !! Utility function to construct a `Diagonal` matrix with constant diagonal element. real ( dp ), intent ( in ) :: d !! Constant diagonal element of the matrix. integer ( ilp ), intent ( in ) :: n !! Dimension of the matrix. type ( Diagonal ) :: A !! Corresponding diagonal matrix. integer :: i A % n = n ; A % dv = [( d , i = 1 , n )] return end function construct_constant_diag module function construct_dense_to_diag ( A ) result ( B ) !! Utility function to construct a `Diagonal` matrix from a rank-2 array. real ( dp ), intent ( in ) :: A (:, :) !! Dense [n x n] matrix from which to construct the `Diagonal` one. type ( Diagonal ) :: B !! Corresponding diagonal matrix. B = Diagonal ( diag ( A )) return end function construct_dense_to_diag !------------------------------------------------------------ !-----     Matrix-vector and matrix-matrix products     ----- !------------------------------------------------------------ pure module function diag_spmv ( A , x ) result ( y ) !! Utility function to compute the matrix-vector product  y = Ax  where  A  !! is of `Diagonal` type and `x` and `y` are both rank-1 arrays. type ( Diagonal ), intent ( in ) :: A !! Input matrix. real ( dp ), intent ( in ) :: x (:) !! Input vector. real ( dp ) :: y ( size ( x )) !! Output vector. integer :: i do concurrent ( i = 1 : size ( x )) y ( i ) = A % dv ( i ) * x ( i ) enddo return end function diag_spmv pure module function diag_multi_spmv ( A , X ) result ( Y ) !! Utility function to compute the matrix-vector product  y = A x  where  A  !! is of `Diagonal` type and `X` and `Y` are both rank-2 arrays. type ( Diagonal ), intent ( in ) :: A !! Input matrix. real ( dp ), intent ( in ) :: X (:, :) !! Input matrix (rank-2 array). real ( dp ) :: Y ( size ( X , 1 ), size ( X , 2 )) !! Output matrix (rank-2 array). integer :: i , j do concurrent ( i = 1 : size ( X , 1 ), j = 1 : size ( X , 2 )) Y ( i , j ) = A % dv ( i ) * X ( i , j ) enddo return end function diag_multi_spmv !---------------------------------- !-----     Linear Algebra     ----- !---------------------------------- pure module function diag_solve ( A , b ) result ( x ) !! Utility function to solve the linear system  A x = b  where  A  is of !! `Diagonal` type and `b` a rank-1 array. The solution `x` is also a rank-1 array !! with the same type and dimension of `b`. type ( Diagonal ), intent ( in ) :: A !! Coefficient matrix. real ( dp ), intent ( in ) :: b (:) !! Right-hande side vector. real ( dp ), allocatable :: x (:) !! Solution vector. integer :: i , n if (. not . allocated ( x )) allocate ( x , mold = b ) do concurrent ( i = 1 : A % n ) x ( i ) = b ( i ) / A % dv ( i ) enddo return end function diag_solve pure module function diag_multi_solve ( A , B ) result ( X ) !! Utility function to solve a linear system with multiple right-hande sides where  A  !! is of `Diagonal` type and `B` a rank-2 array. The solution `X` is also a rank-2 array !! with the same type and dimensions as `B`. type ( Diagonal ), intent ( in ) :: A !! Coefficient matrix. real ( dp ), intent ( in ) :: B (:, :) !! Right-hand side vectors. real ( dp ), allocatable :: X (:, :) !! Solution vectors. integer ( ilp ) :: i , j real ( dp ) :: inv_dv ( A % n ) if (. not . allocated ( X )) allocate ( X , mold = B ); inv_dv = 1.0_dp / A % dv do concurrent ( i = 1 : A % n , j = 1 : size ( B , 2 )) X ( i , j ) = B ( i , j ) * inv_dv ( i ) enddo return end function diag_multi_solve pure module subroutine diag_eig ( A , lambda , vectors ) type ( Diagonal ), intent ( in ) :: A real ( dp ), intent ( out ) :: lambda ( A % n ) real ( dp ), intent ( out ) :: vectors ( A % n , A % n ) lambda = A % dv ; vectors = eye ( A % n ) return end subroutine diag_eig !------------------------------------ !-----     Utility function     ----- !------------------------------------ pure module function diag_to_dense ( A ) result ( B ) !! Utility function to convert a `Diagonal` matrix to a regular rank-2 array. type ( Diagonal ), intent ( in ) :: A !! Input diagonal matrix. real ( dp ) :: B ( A % n , A % n ) !! Output dense rank-2 array. integer :: i B = 0.0_dp do concurrent ( i = 1 : A % n ) B ( i , i ) = A % dv ( i ) enddo end function diag_to_dense pure module function diag_transpose ( A ) result ( B ) !! Utility function to compute the transpose of a `Diagonal` matrix. type ( Diagonal ), intent ( in ) :: A !! Input matrix. type ( Diagonal ) :: B !! Transposed matrix. B = A end function diag_transpose pure module function diag_shape ( A ) result ( shape ) !! Utility function to get the shape of a `Diagonal` matrix. type ( Diagonal ), intent ( in ) :: A !! Input matrix. integer ( ilp ) :: shape ( 2 ) !! Shape of the matrix. shape = A % n return end function diag_shape end submodule DiagonalMatrices","tags":"","loc":"sourcefile/specialmatrices_diagonal.f90.html"},{"title":"specialmatrices_bidiagonal.f90 – SpecialMatrices","text":"Source Code submodule ( SpecialMatrices_Tridiagonal ) BidiagonalMatrices use stdlib_optval , only : optval use stdlib_linalg_lapack , only : gtsv implicit none ( type , external ) contains !-------------------------------- !-----     Constructors     ----- !-------------------------------- pure module function initialize_bidiag ( n , which ) result ( A ) !! Utility function to construct a `Bidiagonal` matrix filled with zeros. integer ( ilp ), intent ( in ) :: n !! Dimension of the matrix. character ( len = 1 ), optional , intent ( in ) :: which !! Whether `A` has a sub- or super-diagonal. type ( Bidiagonal ) :: A !! Corresponding bidiagonal matrix. A % n = n ; A % which = optval ( which , \"L\" ) allocate ( A % dv ( n ), A % ev ( n - 1 )); A % dv = 0.0_dp ; A % ev = 0.0_dp return end function initialize_bidiag pure module function construct_bidiag ( dv , ev , which ) result ( A ) !! Utility function to construct a `Bidiagonal` matrix from rank-1 arrays. real ( dp ), intent ( in ) :: dv (:), ev (:) !! Diagonal elements of the matrix. character ( len = 1 ), optional , intent ( in ) :: which !! Whether `A` has a sub- or super-diagonal. type ( Bidiagonal ) :: A !! Corresponding bidiagonal matrix. A % n = size ( dv ); A % dv = dv ; A % ev = ev ; A % which = optval ( which , \"L\" ) return end function construct_bidiag pure module function construct_constant_bidiag ( d , e , n , which ) result ( A ) !! Utility function to construct a `Bidiagonal` matrix with constant elements. real ( dp ), intent ( in ) :: d , e !! Constant diagonal elements. integer ( ilp ), intent ( in ) :: n !! Dimension of the matrix. character ( len = 1 ), optional , intent ( in ) :: which !! Whether `A` has a sub- or super-diagonal. type ( Bidiagonal ) :: A !! Corresponding bidiagonal matrix. integer :: i A % n = n ; A % which = optval ( which , \"L\" ) A % dv = [( d , i = 1 , n )]; A % ev = [( e , i = 1 , n - 1 )] return end function construct_constant_bidiag !------------------------------------------------------------ !-----     Matrix-vector and Matrix-matrix products     ----- !------------------------------------------------------------ pure module function bidiag_spmv ( A , x ) result ( y ) !! Utility function to compute the matrix-vector product  y = Ax  where  A  !! is of type `Bidiagonal` and `x` and `y` are both rank-1 arrays. type ( Bidiagonal ), intent ( in ) :: A !! Input matrix. real ( dp ), intent ( in ) :: x (:) !! Input vector. real ( dp ) :: y ( size ( x )) !! Output vector. integer ( ilp ) :: i , n n = size ( x ) if ( A % which == \"L\" ) then y ( 1 ) = A % dv ( 1 ) * x ( 1 ) do concurrent ( i = 2 : n ) y ( i ) = A % ev ( i - 1 ) * x ( i - 1 ) + A % dv ( i ) * x ( i ) enddo elseif ( A % which == \"U\" ) then do concurrent ( i = 1 : n - 1 ) y ( i ) = A % dv ( i ) * x ( i ) + A % ev ( i ) * x ( i + 1 ) enddo y ( n ) = A % dv ( n ) * x ( n ) endif return end function bidiag_spmv pure module function bidiag_multi_spmv ( A , X ) result ( Y ) !! Utility function to compute the matrix-matrix product  Y = AX  where  A  !! is of type `Bidiagonal` and `X` and `Y` are both rank-2 arrays. type ( Bidiagonal ), intent ( in ) :: A !! Input matrix. real ( dp ), intent ( in ) :: X (:, :) !! Input matrix (rank-2 array). real ( dp ) :: Y ( size ( X , 1 ), size ( X , 2 )) !! Output matrix (rank-2 array). integer ( ilp ) :: i , n n = size ( x ) do concurrent ( i = 1 : size ( X , 2 )) Y (:, i ) = bidiag_spmv ( A , X (:, i )) enddo return end function bidiag_multi_spmv !---------------------------------- !-----     Linear Algebra     ----- !---------------------------------- pure module function bidiag_solve ( A , b ) result ( x ) !! Utility function to solve the linear system  Ax = b  where  A  is a !! `Bidiagonal` matrix and `b` a rank-1 array. The solution `x` is also a rank-1 !! array with the same type and dimesnion as `b`. type ( Bidiagonal ), intent ( in ) :: A !! Coefficient matrix. real ( dp ), intent ( in ) :: b (:) !! Right-hand side vector. real ( dp ) :: x ( size ( b )) !! Solution vector. real ( dp ) :: dl ( A % n - 1 ), dv ( A % n ), du ( A % n - 1 ), b_ ( A % n , 1 ) integer :: n , nrhs , info ! Initialize array. n = A % n ; b_ (:, 1 ) = b ; nrhs = 1 ; dv = A % dv ! Dispatch based on upper- or lower-bidiagonal. if ( A % which == \"L\" ) then dl = A % ev ; du = 0.0_dp elseif ( A % which == \"U\" ) then dl = 0.0_dp ; du = A % ev endif ! Solve the system using a tridiagonal solver. call gtsv ( n , nrhs , dl , dv , du , b_ , n , info ) ! Return the solution. x = b_ (:, 1 ) return end function bidiag_solve pure module function bidiag_multi_solve ( A , B ) result ( X ) !! Utility function to solve the linear system with multiple right-hand side where !!   A  is a `Bidiagonal` matrix and `B` a rank-2 array. The solution `x` is also !! a rank-2 array with the same type and dimesnion as `B`. type ( Bidiagonal ), intent ( in ) :: A !! Coefficient matrix. real ( dp ), intent ( in ) :: B (:, :) !! Right-hand side vector. real ( dp ) :: X ( size ( B , 1 ), size ( B , 2 )) !! Solution vector. real ( dp ) :: dl ( A % n - 1 ), dv ( A % n ), du ( A % n - 1 ), b_ ( A % n , 1 ) integer ( ilp ) :: n , nrhs , info ! Initialize array. n = A % n ; X = B ; nrhs = size ( X , 2 ); dv = A % dv ! Dispatch based on upper- or lower-bidiagonal. if ( A % which == \"L\" ) then dl = A % ev ; du = 0.0_dp elseif ( A % which == \"U\" ) then dl = 0.0_dp ; du = A % ev endif ! Solve the system using a tridiagonal solver. call gtsv ( n , nrhs , dl , dv , du , X , n , info ) return end function bidiag_multi_solve !------------------------------------ !-----     Utility function     ----- !------------------------------------ pure module function bidiag_shape ( A ) result ( shape ) !! Utility function to return the shape of a `Bidiagonal` matrix. type ( Bidiagonal ), intent ( in ) :: A !! Input matrix. integer ( ilp ) :: shape ( 2 ) !! Shape of the matrix. shape = A % n end function bidiag_shape pure module function bidiag_transpose ( A ) result ( B ) !! Utility function to compute the transpose of a `Bidiagonal` matrix. type ( Bidiagonal ), intent ( in ) :: A !! Input bidiagonal matrix. type ( Bidiagonal ) :: B !! Transpose of the original matrix. B = A if ( A % which == \"L\" ) then B % which = \"U\" else B % which = \"L\" endif return end function bidiag_transpose pure module function bidiag_to_dense ( A ) result ( B ) !! Utility function to convert a `Bidiagonal` matrix to a regular rank-2 array. type ( Bidiagonal ), intent ( in ) :: A !! Input bidiagonal matrix. real ( dp ) :: B ( A % n , A % n ) !! Output dense rank-2 array. integer ( ilp ) :: i , n n = A % n ; B = 0.0_dp if ( A % which == \"L\" ) then B ( 1 , 1 ) = A % dv ( 1 ) do concurrent ( i = 2 : n ) B ( i , i ) = A % dv ( i ) B ( i , i - 1 ) = A % ev ( i - 1 ) enddo elseif ( A % which == \"U\" ) then do concurrent ( i = 1 : n - 1 ) B ( i , i ) = A % dv ( i ) B ( i , i + 1 ) = A % ev ( i ) enddo B ( n , n ) = A % dv ( n ) endif return end function bidiag_to_dense end submodule BidiagonalMatrices","tags":"","loc":"sourcefile/specialmatrices_bidiagonal.f90.html"},{"title":"specialmatrices_tridiagonal.f90 – SpecialMatrices","text":"Source Code module SpecialMatrices_Tridiagonal use stdlib_linalg_constants , only : dp , ilp use stdlib_linalg_state , only : linalg_state_type , linalg_error_handling implicit none private ! --> Linear Algebra. public :: transpose public :: matmul public :: solve ! public :: eig ! --> Utility functions. public :: dense public :: shape !----------------------------------------------------------- !-----     Base types for bi/tri-diagonal matrices     ----- !----------------------------------------------------------- type , public :: Diagonal !! Base type used to define a `Diagonal` matrix of size [n x n] with diagonal given by the !! rank-1 array `dv`. integer ( ilp ) :: n !! Dimension of the matrix. real ( dp ), allocatable :: dv (:) !! Diagonal elements of the matrix. end type type , public :: Bidiagonal !! Base type used to define a `Bidiagonal` matrix of size [n x n] with diagonals given by !! the rank-1 arrays `dv` and `ev`. The character `which` determines whether `ev` defines the !! sub-diagonal (`which = \"L\"`, default) or the super-diagonal (`which = \"U\"`). integer ( ilp ) :: n !! Dimension of the matrix. real ( dp ), allocatable :: dv (:), ev (:) !! Diagonal elements character ( len = 1 ) :: which !! Whether it is lower- or upper-bidiagonal. end type type , public :: Tridiagonal !! Base type used to define a `Tridiagonal` matrix of size [n x n] with diagonal elements !! given by the rank-1 arrays `dl` (sub-diagonal), `d` (diagonal) and `du` (super-diagonal). integer ( ilp ) :: n !! Dimension of the matrix. real ( dp ), allocatable :: d (:), du (:), dl (:) !! Tridiagonal elements. end type type , public :: SymTridiagonal !! Base type used to define a `SymTridiagonal` matrix of size [n x n] with diagonal elements !! given by the rank-1 arrays `dv` (diagonal) and `ev` (sub- and super-diagonal). integer ( ilp ) :: n !! Dimension of the matrix. real ( dp ), allocatable :: dv (:), ev (:) !! Tridiagonal elements. end type !-------------------------------- !-----     Constructors     ----- !-------------------------------- interface Diagonal !! This interface provides different methods to construct a `Diagonal` matrix. !! Only `double precision` is supported currently. Only the diagonal elements !! of  A  are being stored, i.e. !! !!  !!    A !!    = !!    \\begin{bmatrix} !!       d_1 \\\\ !!          &  d_2 \\\\ !!          &     &  \\ddots   \\\\ !!          &     &        &  d_n !!    \\end{bmatrix}. !!  !! !! ### Syntax !! !! - Construct a `Diagonal` matrix filled with zeros: !! !! ```fortran !!    integer, parameter :: n = 100 !!    type(Diagonal) :: A !! !!    A = Diagonal(n) !! ``` !! !! - Construct a `Diagonal` matrix from a vector. !! !! ```fortran !!    integer, parameter :: n = 100 !!    real(dp), allocatable :: dv(:) !!    type(Diagonal) :: A !!    integer :: i !! !!    dv = [(i, i=1, n)]; A = Diagonal(dv) !! ``` !! !! - Construct a `Diagonal` matrix with constant diagonal element. !! !! ```fortran !!    integer, parameter :: n = 100 !!    real(dp), parameter :: d = 2.0_dp !!    type(Diagonal) :: A !! !!    A = Diagonal(d, n) !! ``` !! !! - Construct a `Diagonal` matrix from a standard Fortran rank-2 array. !! !! ```fortran !!    integer, parameter :: n = 100 !!    real(dp) :: B(n, n) !!    type(Diagonal) :: A !! !!    call random_number(B); A = Diagonal(B) !! ``` pure module function initialize_diag ( n ) result ( A ) !! Utility function to construct a `Diagonal` matrix filled with zeros. integer ( ilp ), intent ( in ) :: n !! Dimension of the matrix. type ( Diagonal ) :: A !! Corresponding diagonal matrix. end function initialize_diag pure module function construct_diag ( dv ) result ( A ) !! Utility function to construct a `Diagonal` matrix from a rank-1 array. real ( dp ), intent ( in ) :: dv (:) !! Diagonal elements of the matrix. type ( Diagonal ) :: A !! Corresponding diagonal matrix. end function construct_diag pure module function construct_constant_diag ( d , n ) result ( A ) !! Utility function to construct a `Diagonal` matrix with constant diagonal element. real ( dp ), intent ( in ) :: d !! Constant diagonal element of the matrix. integer ( ilp ), intent ( in ) :: n !! Dimension of the matrix. type ( Diagonal ) :: A !! Corresponding diagonal matrix. end function construct_constant_diag module function construct_dense_to_diag ( A ) result ( B ) !! Utility function to construct a `Diagonal` matrix from a rank-2 array. real ( dp ), intent ( in ) :: A (:, :) !! Dense [n x n] matrix from which to construct the `Diagonal` one. type ( Diagonal ) :: B !! Corresponding diagonal matrix. end function construct_dense_to_diag end interface interface Bidiagonal !! This interface provides different methods to construct a `Bidiagonal` matrix. !! Only `double precision` is supported currently. Only the non-zero elements of !!  A  are stored, i.e. !! !!  !!    A !!    = !!    \\begin{bmatrix} !!       d_1   \\\\ !!       e_1  &  d_2   \\\\ !!             &  \\ddots   &  \\ddots   \\\\ !!             &           &  e_{n-2} &  d_{n-1}  \\\\ !!             &           &           &  e_{n-1} &  d_n !!    \\end{bmatrix}. !!  !! !! #### Syntax !! !! - Construct a `Bidiagonal` matrix filled with zeros: !! !! ```fortran !!    integer, parameter :: n = 100 !!    type(Bidiagonal) :: A !! !!    A = Bidiagonal(n) !! ``` !! !! - Construct a `Bidiagonal` matrix from rank-1 arrays: !! !! ```fortran !!    integer, parameter :: n !!    real(dp), allocatable :: dv(:), ev(:) !!    type(Bidiagonal) :: A !!    integer :: i !! !!    ev = [(i, i=1, n)]; dv = [(2*i, i=1, n)] !!    A = Bidiagonal(dv, ev, which=\"L\") !! ``` !! !! - Construct a `Bidiagonal` matrix with constant diagonals: !! !! ```fortran !!    integer, parameter :: n !!    real(dp), parameter :: e = 1.0_dp, d = 2.0_dp !!    type(Bidiagonal) :: A !! !!    A = Bidiagonal(d, e, n, which=\"L\") !! ``` pure module function initialize_bidiag ( n , which ) result ( A ) !! Utility function to construct a `Bidiagonal` matrix filled with zeros. integer ( ilp ), intent ( in ) :: n !! Dimension of the matrix. character ( len = 1 ), optional , intent ( in ) :: which !! Whether `A` has a sub- or super-diagonal. type ( Bidiagonal ) :: A !! Corresponding bidiagonal matrix. end function initialize_bidiag pure module function construct_bidiag ( dv , ev , which ) result ( A ) !! Utility function to construct a `Bidiagonal` matrix from rank-1 arrays. real ( dp ), intent ( in ) :: dv (:), ev (:) !! Diagonal elements of the matrix. character ( len = 1 ), optional , intent ( in ) :: which !! Whether `A` has a sub- or super-diagonal. type ( Bidiagonal ) :: A !! Corresponding bidiagonal matrix. end function construct_bidiag pure module function construct_constant_bidiag ( d , e , n , which ) result ( A ) !! Utility function to construct a `Bidiagonal` matrix with constant elements. real ( dp ), intent ( in ) :: d , e !! Constant diagonal elements. integer ( ilp ), intent ( in ) :: n !! Dimension of the matrix. character ( len = 1 ), optional , intent ( in ) :: which !! Whether `A` has a sub- or super-diagonal. type ( Bidiagonal ) :: A !! Corresponding bidiagonal matrix. end function construct_constant_bidiag end interface interface Tridiagonal !! This interface provides different methods to construct a `Tridiagonal` matrix. !! Only `double precision` is supported currently. Only the non-zero elements of !!  A  are stored, i.e. !! !!  !!    A !!    = !!    \\begin{bmatrix} !!       d_1   &  du_1  \\\\ !!       dl_1  &  d_2      &  du_2  \\\\ !!             &  \\ddots   &  \\ddots   &  \\ddots   \\\\ !!             &           &  dl_{n-2} &  d_{n-1}  &  du_{n-1} \\\\ !!             &           &           &  dl_{n-1} &  d_n !!    \\end{bmatrix}. !!  !! !! #### Syntax !! !! - Construct a `Tridiagonal` matrix filled with zeros: !! !! ```fortran !!    integer, parameter :: n = 100 !!    type(Tridiagonal) :: A !! !!    A = Tridiagonal(n) !! ``` !! !! - Construct a `Tridiagonal` matrix from rank-1 arrays: !! !! ```fortran !!    integer, parameter :: n !!    real(dp), allocatable :: dl(:), d(:), du(:) !!    type(Tridiagonal) :: A !!    integer :: i !! !!    dl = [(i, i=1, n)]; d = [(2*i, i=1, n)]; dl = [(3*i, i=1, n)] !!    A = Tridiagonal(dl, d, du) !! ``` !! !! - Construct a `Tridiagonal` matrix with constant diagonals: !! !! ```fortran !!    integer, parameter :: n !!    real(dp), parameter :: dl = 1.0_dp, d = 2.0_dp, du = 3.0_dp !!    type(Tridiagonal) :: A !! !!    A = Tridiagonal(dl, d, du, n) !! ``` !! !! - Construct a `Tridiagonal` matrix from a standard Fortran rank-2 array: !! !! ```fortran !!    integer, parameter :: n = 100 !!    real(dp) :: B(n, n) !!    type(Tridiagonal) :: A !! !!    call random_number(B); A = Tridiagonal(B) !! ``` pure module function initialize_tridiag ( n ) result ( A ) !! Utility function to construct a `Tridiagonal` matrix filled with zeros. integer ( ilp ), intent ( in ) :: n !! Dimension of the matrix. type ( Tridiagonal ) :: A !! Corresponding tridiagonal matrix. end function initialize_tridiag pure module function construct_tridiag ( dl , d , du ) result ( A ) !! Utility function to construct a `Tridiagonal` matrix from a set of rank-1 arrays. real ( dp ), intent ( in ) :: dl (:), d (:), du (:) !! Diagonal elements of the matrix. type ( Tridiagonal ) :: A !! Corresponding tridiagonal matrix. end function construct_tridiag pure module function construct_constant_tridiag ( l , d , u , n ) result ( A ) !! Utility function to construct a `Tridiagonal` matrix with constant elements. real ( dp ), intent ( in ) :: l , d , u !! Constant diagonal elements. integer ( ilp ), intent ( in ) :: n !! Dimension of the matrix. type ( Tridiagonal ) :: A !! Corresponding tridiagonal matrix. end function construct_constant_tridiag module function construct_dense_to_tridiag ( A ) result ( B ) !! Utility function to construct a `Tridiagonal` matrix from a rank-2 array. real ( dp ), intent ( in ) :: A (:, :) !! Dense [n x n] matrix from which to construct the `Tridiagonal` one. type ( Tridiagonal ) :: B !! Corresponding tridiagonal matrix. end function construct_dense_to_tridiag end interface interface SymTridiagonal !! This interface provides different methods to construct a `SymTridiagonal` matrix. !! Only `double precision` is supported currently. Only the non-zero elements of !!  A  are stored, i.e. !! !!  !!    A !!    = !!    \\begin{bmatrix} !!       d_1   &  e_1  \\\\ !!       e_1  &  d_2      &  e_2  \\\\ !!             &  \\ddots   &  \\ddots   &  \\ddots   \\\\ !!             &           &  e_{n-2} &  d_{n-1}  &  e_{n-1} \\\\ !!             &           &           &  e_{n-1} &  d_n !!    \\end{bmatrix}. !!  !! !! #### Syntax !! !! - Construct a `SymTridiagonal` matrix filled with zeros: !! !! ```fortran !!    integer, parameter :: n = 100 !!    type(SymTridiagonal) :: A !! !!    A = SymTridiagonal(n) !! ``` !! !! - Construct a `SymTridiagonal` matrix from rank-1 arrays: !! !! ```fortran !!    integer, parameter :: n !!    real(dp), allocatable :: ev(:), dv(:) !!    type(SymTridiagonal) :: A !!    integer :: i !! !!    dv = [(i, i=1, n)]; ev = [(2*i, i=1, n)] !!    A = Tridiagonal(dv, ev) !! ``` !! !! - Construct a `SymTridiagonal` matrix with constant diagonals: !! !! ```fortran !!    integer, parameter :: n !!    real(dp), parameter :: d = 1.0_dp, e = 2.0_dp !!    type(SymTridiagonal) :: A !! !!    A = SymTridiagonal(d, e, n) !! ``` pure module function initialize_symtridiag ( n ) result ( A ) !! Utility function to create a `SymTridiagonal` matrix filled with zeros. integer ( ilp ), intent ( in ) :: n !! Dimension of the matrix. type ( SymTridiagonal ) :: A !! Corresponding symmetric tridiagonal matrix. end function initialize_symtridiag pure module function construct_symtridiag ( dv , ev ) result ( A ) !! Utility function to create a `SymTridiagonal` matrix from rank-1 arrays. real ( dp ), intent ( in ) :: dv (:), ev (:) !! Diagonal elements of the matrix. type ( SymTridiagonal ) :: A !! Corresponding symmetric tridiagonal matrix. end function construct_symtridiag pure module function construct_constant_symtridiag ( d , e , n ) result ( A ) !! Utility function to create a `SymTridiagonal` matrix with constant diagonal elements. real ( dp ), intent ( in ) :: d , e !! Constant diagonal elements of the matrix. integer ( ilp ), intent ( in ) :: n !! Dimension of the matrix. type ( SymTridiagonal ) :: A !! Corresponding symmetric tridiagonal matrix. end function construct_constant_symtridiag end interface !------------------------------------------------------------ !-----     Matrix-vector and Matrix-matrix products     ----- !------------------------------------------------------------ interface matmul !! This interface overloads the Fortran intrinsic `matmul` for the following types: !! !! - `Diagonal` !! - `Bidiagonal` !! - `Tridiagonal` !! - `SymTridiagonal` !! !! The intrinsic `matmul` is overloaded both for matrix-vector and matrix-matrix products. !! For a matrix-matrix product  C = AB , only the matrix  A  has to be of the ones !! of the types defined by `SpecialMatrices`. Both  B  and  C  need to be standard !! Fortran rank-2 arrays. All the underlying functions are defined as `pure`. !! !! #### Syntax !! !! - For matrix-vector product with `A` being of a type defined by `SpecialMatrices` and !! `x` a standard rank-1 array: !! ```fortran !!    matmul(A, x) !! ``` !! !! - For matrix-matrix product with `A` being of a type defined by `SpecialMatrices` and !! `B` a rank-2 array: !! ```fortran !!    matmul(A, B) !! ``` pure module function diag_spmv ( A , x ) result ( y ) !! Utility function to compute the matrix-vector product  y = Ax  where  A  !! is of `Diagonal` type and `x` and `y` are both rank-1 arrays. type ( Diagonal ), intent ( in ) :: A !! Input matrix. real ( dp ), intent ( in ) :: x (:) !! Input vector. real ( dp ) :: y ( size ( x )) !! Output vector. end function diag_spmv pure module function diag_multi_spmv ( A , X ) result ( Y ) !! Utility function to compute the matrix-vector product  y = Ax  where  A  !! is of `Diagonal` type and `X` and `Y` are both rank-2 arrays. type ( Diagonal ), intent ( in ) :: A !! Input matrix. real ( dp ), intent ( in ) :: X (:, :) !! Input matrix (rank-2 array). real ( dp ) :: Y ( size ( X , 1 ), size ( X , 2 )) !! Output matrix (rank-2 array). end function diag_multi_spmv pure module function bidiag_spmv ( A , x ) result ( y ) !! Utility function to compute the matrix-vector product  y = Ax  where  A  !! is of `Bidiagonal` type and `x` and `y` are both rank-1 arrays. type ( Bidiagonal ), intent ( in ) :: A !! Input matrix. real ( dp ), intent ( in ) :: x (:) !! Input vector. real ( dp ) :: y ( size ( x )) !! Output vector. end function bidiag_spmv pure module function bidiag_multi_spmv ( A , X ) result ( Y ) !! Utility function to compute the matrix-matrix product  Y = AX  where  A  !! is of `Bidiagonal` type and `X` and `Y` are both rank-2 arrays. type ( Bidiagonal ), intent ( in ) :: A !! Input matrix. real ( dp ), intent ( in ) :: X (:, :) !! Input matrix (rank-2 array). real ( dp ) :: Y ( size ( X , 1 ), size ( X , 2 )) !! Output matrix (rank-2 array). end function bidiag_multi_spmv pure module function tridiag_spmv ( A , x ) result ( y ) !! Utility function to compute the matrix-vector product  y = Ax  where  A  !! is of `Tridiagonal` type and `x` and `y` are both rank-1 arrays. type ( Tridiagonal ), intent ( in ) :: A !! Input matrix. real ( dp ), intent ( in ) :: x (:) !! Input vector. real ( dp ) :: y ( size ( x )) !! Output vector. end function tridiag_spmv pure module function tridiag_multi_spmv ( A , X ) result ( Y ) !! Utility function to compute the matrix-vector product  y = Ax  where  A  !! is of `Tridiagonal` type and `X` and `Y` are both rank-2 arrays. type ( Tridiagonal ), intent ( in ) :: A !! Input matrix. real ( dp ), intent ( in ) :: X (:, :) !! Input matrix (rank-2 array). real ( dp ) :: Y ( size ( X , 1 ), size ( X , 2 )) !! Output matrix (rank-2 array). end function tridiag_multi_spmv pure module function symtridiag_spmv ( A , x ) result ( y ) !! Utility function to compute the matrix-vector product  y = Ax  where  A  !! is of `SymTridiagonal` type and `x` and `y` are both rank-1 arrays. type ( SymTridiagonal ), intent ( in ) :: A !! Input matrix. real ( dp ), intent ( in ) :: x (:) !! Input vector. real ( dp ) :: y ( size ( x )) !! Output vector. end function symtridiag_spmv pure module function symtridiag_multi_spmv ( A , X ) result ( Y ) !! Utility function to compute the matrix-matrix product  Y = AX  where  A  !! is of `SymTridiagonal` type and `X` and `Y` are both rank-2 arrays. type ( SymTridiagonal ), intent ( in ) :: A real ( dp ), intent ( in ) :: X (:, :) real ( dp ) :: Y ( size ( X , 1 ), size ( X , 2 )) end function symtridiag_multi_spmv end interface !---------------------------------- !-----     Linear Algebra     ----- !---------------------------------- interface solve !! This interface overloads the `solve` interface from `stdlib_linalg` for solving a linear !! system  Ax = b  where  A  is of one of the types provided by `SpecialMatrices`. !! It also enables to solve a linear system with multiple right-hand sides. !! !! #### Syntax !! !! To solve a system with  A  being of one of the types defined by `SpecialMatrices`: !! !! ```fortran !!    y = solve(A, x) !! ``` !! !! #### Arguments !! !! `A`   :  Matrix of `Diagonal`, `Bidiagonal`, `Tridiagonal` or `SymTridiagonal` type. !!          It is an `intent(in)` argument. !! !! `x`   :  Rank-1 or rank-2 array defining the right-hand side(s). It is an `intent(in)` !!          argument. !! !! `y`   :  Solution of the linear system. It has the same type and shape as `x`. pure module function diag_solve ( A , b ) result ( x ) !! Utility function to solve the linear system  A x = b  where  A  is of !! `Diagonal` type and `b` a rank-1 array. The solution `x` is also a rank-1 array !! with the same type and dimension as `b`. type ( Diagonal ), intent ( in ) :: A !! Coefficient matrix. real ( dp ), intent ( in ) :: b (:) !! Right-hande side vector. real ( dp ), allocatable :: x (:) !! Solution vector. end function diag_solve pure module function diag_multi_solve ( A , B ) result ( X ) !! Utility function to solve a linear system with multiple right-hand sides where !!  A  is of `Diagonal` type and `B` a rank-2 array. The solution `X` is also a !! rank-2 array with the same type and dimensions as `B`. type ( Diagonal ), intent ( in ) :: A !! Coefficient matrix. real ( dp ), intent ( in ) :: B (:, :) !! Right-hande side vectors. real ( dp ), allocatable :: X (:, :) !! Solution vectors. end function diag_multi_solve ! Bidiagonal matrix solve. pure module function bidiag_solve ( A , b ) result ( x ) !! Utility function to solve a linear system  Ax = b  where  A  is of !! `Bidiagonal` type and `b` a rank-1 array. The solution `x` is also a rank-1 array !! with the same type and dimension as `b`. type ( Bidiagonal ), intent ( in ) :: A !! Coefficient matrix. real ( dp ), intent ( in ) :: b (:) !! Right-hand side vector. real ( dp ) :: x ( size ( b )) !! Solution vector. end function bidiag_solve pure module function bidiag_multi_solve ( A , B ) result ( X ) !! Utility function to solve a linear system with multiple right-hand sides where !!  A  is of `Bidiagonal` type and `B` a rank-2 array. The solution `X` is also !! a rank-2 array with the same type and dimensions as `B`. type ( Bidiagonal ), intent ( in ) :: A !! Coefficient matrix. real ( dp ), intent ( in ) :: B (:, :) !! Right-hand side vectors. real ( dp ) :: X ( size ( B , 1 ), size ( B , 2 )) !! Solution vectors. end function bidiag_multi_solve ! Tridiagonal matrix solve. pure module function tridiag_solve ( A , b ) result ( x ) !! Utility function to solve the linear system  Ax = b  where  A  is of !! `Tridiagonal` type and `b` a rank-1 array. The solution `x` is also a rank-1 !! array with the same type and dimension as `b`. type ( Tridiagonal ), intent ( in ) :: A !! Coefficient matrix. real ( dp ), intent ( in ) :: b (:) !! Right-hand side vector. real ( dp ) :: x ( size ( b )) !! Solution vector. end function tridiag_solve pure module function tridiag_multi_solve ( A , B ) result ( X ) !! Utility function to solve a linear system with multiple right-hand sides where !!  A  is of `Tridiagonal` type and `B` a rank-2 array. The solution `X` is also !! a rank-2 array with the same type and dimensions as `B`. type ( Tridiagonal ), intent ( in ) :: A !! Coefficient matrix. real ( dp ), intent ( in ) :: B (:, :) !! Right-hand side vectors. real ( dp ) :: X ( size ( B , 1 ), size ( B , 2 )) !! Solution vectors. end function tridiag_multi_solve ! Symmetric Tridiagonal matrix solve. pure module function symtridiag_solve ( A , b ) result ( x ) !! Utility function to solve the linear system  Ax = b  where  A  is of !! `SymTridiagonal` type and `b` a rank-1 array. The solution `x` is also a rank-1 !! array with the same type and dimension as `b`. type ( SymTridiagonal ), intent ( in ) :: A !! Coefficient matrix. real ( dp ), intent ( in ) :: b (:) !! Right-hande side vector. real ( dp ) :: x ( size ( b )) !! Solution vector. end function symtridiag_solve pure module function symtridiag_multi_solve ( A , B ) result ( X ) !! Utility function to solve a linear system with multiple right-hand side vectors !! where  A  is of `SymTridiagonal` type and `B` a rank-2 array. The solution `X` !! is also a rank-2 array with the same type and dimensions as `B`. type ( SymTridiagonal ), intent ( in ) :: A !! Coefficient matrix. real ( dp ), intent ( in ) :: B (:, :) !! Right-hand side vectors. real ( dp ) :: X ( size ( B , 1 ), size ( B , 2 )) !! Solution vectors. end function symtridiag_multi_solve end interface interface eig !! This interface overloads the `eig` interface from `stdlib_linalg` for solving a !! generalized eigenvalue problem  A x = \\lambda x  where  A  is of one of the types !! provided by `SpecialMatrices`. Whenever possible, eigensolvers specialized for the !! particular matrix structure are being used. If not,  A  is converted to a standard !! rank-2 array and the eigenpairs are computed using the `eig` from `stdlib_linalg`. !! !! #### Syntax !! !! ```fortran !!    call eig(A, lambda, vectors) !! ``` !! !! #### Arguments !! !! `A`   :  Matrix of `Diagonal`, `Bidiagonal`, `Tridiagonal` or `SymTridiagonal` type. It !!          is an `intent(in)` argument. !! !! `lambda` :  `complex` rank-1 array containing the eigenvalues of  A . It is an !!             `intent(out)` argument. !! !! `vectors`   :  `complex` rank-2 array containing th eigenvectors of  A . It is an !!                `intent(out)` argument. pure module subroutine diag_eig ( A , lambda , vectors ) type ( Diagonal ), intent ( in ) :: A !! Input matrix. real ( dp ), intent ( out ) :: lambda ( A % n ) !! Eigenvalues. real ( dp ), intent ( out ) :: vectors ( A % n , A % n ) !! Eigenvectors. end subroutine diag_eig end interface !------------------------------------- !-----     Utility functions     ----- !------------------------------------- interface dense !! This interface provides methods to convert a matrix of one the types defined in !! `SpecialMatrix` to a regular rank-2 array. !! !! #### Syntax !! !! ```fortran !!    B = dense(A) !! ``` !! !! #### Arguments !! !! `A`   :  Matrix of `Diagonal`, `Bidiagonal`, `Tridiagonal` or `SymTridiagonal` type. !!          It is an `intent(in)` argument. !! !! `B`   :  Rank-2 array representation of the matrix  A . pure module function diag_to_dense ( A ) result ( B ) !! Utility function to convert a `Diagonal` matrix to a regular rank-2 array. type ( Diagonal ), intent ( in ) :: A !! Input diagonal matrix. real ( dp ) :: B ( A % n , A % n ) !! Output dense rank-2 array. end function diag_to_dense pure module function bidiag_to_dense ( A ) result ( B ) !! Utility function to convert a `Bidiagonal` matrix to a regular rank-2 array. type ( Bidiagonal ), intent ( in ) :: A !! Input bidiagonal matrix. real ( dp ) :: B ( A % n , A % n ) !! Output dense rank-2 array. end function bidiag_to_dense pure module function tridiag_to_dense ( A ) result ( B ) !! Utility function to convert a `Tridiagonal` matrix to a regular rank-2 array. type ( Tridiagonal ), intent ( in ) :: A !! Input tridiagonal matrix. real ( dp ) :: B ( A % n , A % n ) !! Output dense rank-2 array. end function tridiag_to_dense pure module function symtridiag_to_dense ( A ) result ( B ) !! Utility function to convert a `SymTridiagonal` matrix to a regular rank-2 array. type ( SymTridiagonal ), intent ( in ) :: A !! Input symmetric tridiagonal matrix. real ( dp ) :: B ( A % n , A % n ) !! Output dense rank-2 array. end function symtridiag_to_dense end interface interface transpose !! This interface overloads the Fortran `intrinsic` procedure to define the transpose !! operation for the various types defined in `SpecialMatrices`. !! !! #### Syntax !! !! ```fortran !!    B = transpose(A) !! ``` !! !! #### Arguments !! !! `A`   :  Matrix of `Diagonal`, `Bidiagonal`, `Tridiagonal` or `SymTridiagonal` type. !!          It is an `intent(in)` argument. !! !! `B`   :  Resulting transposed matrix. It is of the same type as `A`. pure module function diag_transpose ( A ) result ( B ) !! Utility function to compute the transpose of a `Diagonal` matrix. !! The output matrix is also of `Diagonal` type. type ( Diagonal ), intent ( in ) :: A !! Input Diagonal matrix. type ( Diagonal ) :: B !! Tranpose of the original diagonal matrix. end function diag_transpose pure module function bidiag_transpose ( A ) result ( B ) !! Utility function to compute the transpose of a `Bidiagonal` matrix. !! The output matrix is also of `Bidiagonal` type. type ( Bidiagonal ), intent ( in ) :: A !! Input bidiagonal matrix. type ( Bidiagonal ) :: B !! Transpose of the original diagonal matrix. end function bidiag_transpose pure module function tridiag_transpose ( A ) result ( B ) !! Utility function to compute the tranpose of a `Tridiagonal` matrix. !! The output matrix is also of `Tridiagonal` type. type ( Tridiagonal ), intent ( in ) :: A !! Input tridiagonal matrix. type ( Tridiagonal ) :: B !! Transpose of the original tridiagonal matrix. end function tridiag_transpose pure module function symtridiag_transpose ( A ) result ( B ) !! Utility function to compute the transpose of a `SymTridiagonal` matrix. !! The output matrix is also of `SymTridiagonal` type. type ( SymTridiagonal ), intent ( in ) :: A !! Input symmetric tridiagonal matrix. type ( SymTridiagonal ) :: B !! Transpose of the original matrix. end function symtridiag_transpose end interface interface shape !! This interface provides methods to access the shape of a matrix  A  of one of !! the types defined by `SpecialMatrices`. !! !! #### Syntax !! !! ```fortran !!    shape(A) !! ``` pure module function diag_shape ( A ) result ( shape ) !! Utility function to get the shape of a `Diagonal` matrix. type ( Diagonal ), intent ( in ) :: A !! Input matrix. integer ( ilp ) :: shape ( 2 ) !! Shape of the matrix. end function diag_shape pure module function bidiag_shape ( A ) result ( shape ) !! Utility function to get the shape of a `Bidiagonal` matrix. type ( Bidiagonal ), intent ( in ) :: A !! Input matrix. integer ( ilp ) :: shape ( 2 ) !! Shape of the matrix. end function bidiag_shape pure module function tridiag_shape ( A ) result ( shape ) !! Utility function to get the shape of a `Tridiagonal` matrix. type ( Tridiagonal ), intent ( in ) :: A !! Input matrix. integer ( ilp ) :: shape ( 2 ) !! Shape of the matrix. end function tridiag_shape pure module function symtridiag_shape ( A ) result ( shape ) !! Utility function to get the shape of a `SymTridiagonal` matrix. type ( SymTridiagonal ), intent ( in ) :: A !! Input matrix. integer ( ilp ) :: shape ( 2 ) !! Shape of the matrix. end function symtridiag_shape end interface contains end module SpecialMatrices_Tridiagonal","tags":"","loc":"sourcefile/specialmatrices_tridiagonal.f90.html"}]}